    -- RFC
    IJ_DB_DUNGEON_RFC_NAME = "Огненная пропасть ярости"
    IJ_DB_DUNGEON_RFC_STORY =
    "Пропасть Яростного Огня представляет собой сеть вулканических пещер, лежащих под новой столицей орков Оргриммером. Недавно распространились слухи, что культ, верный демоническому Совету Теней, поселился в огненных глубинах Пропасти. Этот культ, известный как Пылающий Клинок, угрожает самому суверенитету Дуротара. Многие полагают, что вождь орков Тралл знает о существовании Клинка и решил не уничтожать его в надежде, что его члены могут привести его прямо к Теневому Совету. В любом случае, темные силы, исходящие из Огненной Пропасти Ярости, могут уничтожить все, за что боролись орки."

    -- RFC Bosses
    IJ_DB_DUNGEON_RFC_BOSS_NAME_11517 = "Огглфлинт"
    IJ_DB_DUNGEON_RFC_BOSS_STORY_11517 =
    "Оглфлинт и другие трогги отступили на верхние уровни Огненной Пропасти Ярости, как только туда вошли культисты Пылающего Клинка."
    IJ_DB_DUNGEON_RFC_BOSS_11517_ABILITY_NAME_845 = "Раскалывать"
    IJ_DB_DUNGEON_RFC_BOSS_11517_ABILITY_EFFECT_845 = "Огглфлинт рассекает всех врагов перед собой."
    IJ_DB_DUNGEON_RFC_BOSS_NAME_11520 = "Тарагаман Голодный"
    IJ_DB_DUNGEON_RFC_BOSS_STORY_11520 =
    "Тарагамана, которого считают лидером «Пылающего клинка», можно найти прячущимся в огненных глубинах Огненной пропасти Ярости и использующим свое демоническое влияние для развращения жителей Оргриммара."
    IJ_DB_DUNGEON_RFC_BOSS_11520_ABILITY_NAME_11970 = "Кольцо Огня"
    IJ_DB_DUNGEON_RFC_BOSS_11520_ABILITY_EFFECT_11970 = "Тарагаман Ненасытный наносит урон от огня ближайшим врагам."
    IJ_DB_DUNGEON_RFC_BOSS_11520_ABILITY_NAME_18072 = "Апперкот"
    IJ_DB_DUNGEON_RFC_BOSS_11520_ABILITY_EFFECT_18072 = "Тарагаман Голодный бьет врага кулаком, отбрасывая его назад."
    IJ_DB_DUNGEON_RFC_BOSS_NAME_11518 = "Джергош Призыватель"
    IJ_DB_DUNGEON_RFC_BOSS_STORY_11518 =
    "Джергош Призыватель отверг идеалы орков и практикует темное и демоническое искусство чернокнижника. Лидер культистов Пылающего Клинка, Джергош обитает в Огненной Пропасти Ярости, придумывая план, достаточно опасный, чтобы привлечь внимание самого Тралла."
    IJ_DB_DUNGEON_RFC_BOSS_11518_ABILITY_NAME_348 = "Приносить в жертву"
    IJ_DB_DUNGEON_RFC_BOSS_11518_ABILITY_EFFECT_348 =
    "Джергош Призыватель поджигает врага, нанося ему постепенный урон от огня."
    IJ_DB_DUNGEON_RFC_BOSS_11518_ABILITY_NAME_702 = "Проклятие слабости"
    IJ_DB_DUNGEON_RFC_BOSS_11518_ABILITY_EFFECT_702 =
    "Джергош Призыватель проклинает врага, уменьшая наносимый им физический урон на 30 секунд."
    IJ_DB_DUNGEON_RFC_BOSS_NAME_11519 = "Баззалан"
    IJ_DB_DUNGEON_RFC_BOSS_STORY_11519 =
    "Баззалан возглавляет культистов Пылающего Клинка вместе с Джергошем Призывателем. Его мотивы неясны, но, как и все сатиры, он быстрый и хитрый враг."
    IJ_DB_DUNGEON_RFC_BOSS_11519_ABILITY_NAME_744 = "Яд"
    IJ_DB_DUNGEON_RFC_BOSS_11519_ABILITY_EFFECT_744 =
    "Баззалан отравляет врага, нанося периодический урон от сил природы."
    IJ_DB_DUNGEON_RFC_BOSS_11519_ABILITY_NAME_14873 = "Зловещий удар"
    IJ_DB_DUNGEON_RFC_BOSS_11519_ABILITY_EFFECT_14873 = "Баззалан поражает врага, нанося ему физический урон."

    -- Stockades
    IJ_DB_DUNGEON_STOCKADES_NAME = "Частокол"
    IJ_DB_DUNGEON_STOCKADES_STORY =
    "Частоколы — это тюремный комплекс строгого режима, спрятанный под районом каналов города Штормград. Частоколы, которыми управляет начальник тюрьмы Телуотер, являются домом для мелких преступников, политических повстанцев, убийц и множества самых опасных преступников в стране. Недавно восстание под руководством заключенных привело к хаосу в частоколах, где охранники были изгнаны, а заключенные бродят на свободе. Начальнику тюрьмы Телуотеру удалось сбежать из зоны задержания, и в настоящее время он набирает отважных искателей острых ощущений, чтобы они отправились в тюрьму и убили вдохновителя восстания - хитрого преступника Базила Тредда."

    -- Stockades Bosses
    IJ_DB_DUNGEON_STOCKADES_BOSS_NAME_1696 = "Таргорр Ужасающий"
    IJ_DB_DUNGEON_STOCKADES_BOSS_STORY_1696 =
    "Таргорр Ужасный служил оркам Черной горы под предводительством Гат'Илзогга в качестве верховного палача. Его методы были безжалостны даже по орочьим стандартам. Людей, которые храбро сражались, защищая Штормград, подвергали пыткам по его прихоти. Таргорр был схвачен и отправлен в частокол, однако из-за коррумпированной и неэффективной правовой системы он не был казнен так, как того заслуживали его действия. Во время восстания в частоколе безжалостный орк присоединился к бунтовщикам Справедливости."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1696_ABILITY_NAME_8599 = "Разгневать"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1696_ABILITY_EFFECT_8599 =
    "Таргорр Ужасный приходит в ярость, увеличивая свой физический урон и скорость атаки на 2 минуты."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1696_ABILITY_NAME_3417 = "Трэш"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1696_ABILITY_EFFECT_3417 =
    "Таргорр Ужасающий получает шанс нанести две дополнительные атаки."
    IJ_DB_DUNGEON_STOCKADES_BOSS_NAME_1666 = "Кэм Дипфури"
    IJ_DB_DUNGEON_STOCKADES_BOSS_STORY_1666 =
    "Кам Глубинная Ярость, по данным разведки Альянса в Дун Модре, установлен как организатор взрыва, разрушившего один из мостов в Тандол-пролете, а также гибели одного из родственников Длиннокоса Мрачного. В отличие от большинства других заключенных в частоколе, он не является членом Братства Справедливости."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1666_ABILITY_NAME_7164 = "Оборонительная позиция"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1666_ABILITY_EFFECT_7164 =
    "Кам Глубинная Ярость принимает защитную стойку, уменьшая получаемый урон."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1666_ABILITY_NAME_8242 = "Удар щитом"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1666_ABILITY_EFFECT_8242 =
    "Кам Глубинная Ярость бьет своим щитом по врагу, нанося ему урон и оглушая его на 2 секунды."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1666_ABILITY_NAME_871 = "Стена щитов"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1666_ABILITY_EFFECT_871 =
    "Кам Глубинная Ярость поднимает свой щит, уменьшая весь получаемый урон на 60% на 12 секунд."
    IJ_DB_DUNGEON_STOCKADES_BOSS_NAME_1717 = "Хэмхок"
    IJ_DB_DUNGEON_STOCKADES_BOSS_STORY_1717 =
    "По Штормграду распространились слухи о том, что Хэмхок был захваченным огром из Сумеречного леса, что, возможно, сделало его огром Расколотого Кулака. Если бы это было правдой, он, возможно, попал бы под командование Ззарк'Вула, лидера клана Огрского кургана Вул'Гол. Альтернативно, он мог быть захваченным членом Братства Справедливости."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1717_ABILITY_NAME_6742 = "Жажда крови"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1717_ABILITY_EFFECT_6742 =
    "Хэмок охвачен жаждой крови, увеличивая скорость атаки его и его союзников на 30% на 30 секунд."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1717_ABILITY_NAME_421 = "Цепная молния"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1717_ABILITY_EFFECT_421 =
    "Хэмхок бросает молнию во врага, прыгая к двум другим целям и нанося от 190 до 220 урона от сил природы каждой."
    IJ_DB_DUNGEON_STOCKADES_BOSS_NAME_1716 = "Базил Тредд"
    IJ_DB_DUNGEON_STOCKADES_BOSS_STORY_1716 =
    "Базил Тредд — лейтенант и самый доверенный помощник Эдвина Ван Клифа. Он был пойман во время беспорядков, приведших к гибели королевы Тиффин, и заключен в тюрьму, а позже возглавил бандитов Братства Справедливости в частоколе."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1716_ABILITY_NAME_9128 = "Боевой крик"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1716_ABILITY_EFFECT_9128 =
    "Базил Тредд кричит, усиливая его и других союзников, предоставляя им дополнительную силу атаки в ближнем бою на 2 минуты."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1716_ABILITY_NAME_7964 = "Дымовая бомба"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1716_ABILITY_EFFECT_7964 =
    "Базил Тредд бросает дымовую шашку, оглушающую всех ближайших врагов на 4 секунды."
    IJ_DB_DUNGEON_STOCKADES_BOSS_NAME_1720 = "Брейгал Железный Накл"
    IJ_DB_DUNGEON_STOCKADES_BOSS_STORY_1720 =
    "Неуловимый гном, которого редко можно увидеть среди заключенных в частоколах Штормграда. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_STOCKADES_BOSS_NAME_1663 = "Декстрэн Уорд"
    IJ_DB_DUNGEON_STOCKADES_BOSS_STORY_1663 =
    "Уорд был пойман на краже тел с кладбища Рэйвен-Хилл и продаже их Морбенту Фелу, преступление, которое в конечном итоге привело к его поимке и мрачной славе."
    IJ_DB_DUNGEON_STOCKADES_BOSS_1663_ABILITY_NAME_5246 = "Пугающий крик"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1663_ABILITY_EFFECT_5246 =
    "Декстрен Уорд кричит на ближайших врагов, заставляя их в страхе бежать в течение 6 секунд. ||н||  ||н|| Обязательно очистите комнаты вокруг места встречи, иначе вы можете случайно сорваться с места, находясь в страхе!"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1663_ABILITY_NAME_11976 = "Ударять"
    IJ_DB_DUNGEON_STOCKADES_BOSS_1663_ABILITY_EFFECT_11976 =
    "Дектрен Уорд наносит своей цели дополнительный физический урон."

    -- SV
    IJ_DB_DUNGEON_SV_NAME = "Хранилище Штормграда"
    IJ_DB_DUNGEON_SV_STORY =
    "Хранилище Штормграда было построено для хранения самых опасных преступников и магических угроз королевства. В его сердце лежит Арк'Тирас, мощный кристалл, который свел с ума стражников и испортил рунические конструкции, предназначенные для патрулирования его залов. Теперь Хранилище представляет собой лабиринт хаоса..."

    -- SV Bosses
    IJ_DB_DUNGEON_SV_BOSS_NAME_80853 = "Азош Мрачное Пламя"
    IJ_DB_DUNGEON_SV_BOSS_STORY_80853 =
    "Азош Мрачное Пламя когда-то был некролитом Совета Теней, воспитанным Гул'даном в качестве рыцаря смерти. Теперь он командует костями павших и истощает силы всех, кто противостоит ему. Его темное присутствие исказило залы Убежища, и только смелые могут надеяться остановить его неустанную жажду власти."
    IJ_DB_DUNGEON_SV_BOSS_80853_ABILITY_NAME_10212 = "Чародейские стрелы"
    IJ_DB_DUNGEON_SV_BOSS_80853_ABILITY_EFFECT_10212 =
    "Азош Мрачное Пламя запускает во врага чародейские снаряды, нанося 192 ед. тайного урона каждую 1 секунду в течение 5 секунд."
    IJ_DB_DUNGEON_SV_BOSS_80853_ABILITY_NAME_18702 = "Проклятие Темного Мастера"
    IJ_DB_DUNGEON_SV_BOSS_80853_ABILITY_EFFECT_18702 =
    "Азош Мрачное Пламя проклинает своих врагов, уменьшая их силу и выносливость на 50 на 60 секунд."
    IJ_DB_DUNGEON_SV_BOSS_NAME_80852 = "Там'Грарр"
    IJ_DB_DUNGEON_SV_BOSS_STORY_80852 =
    "О Там'Грарре известно немногое, кроме того, что он грозный огр, известный своей жестокой силой и жестоким нравом."
    IJ_DB_DUNGEON_SV_BOSS_80852_ABILITY_NAME_5246 = "Устрашающий крик"
    IJ_DB_DUNGEON_SV_BOSS_80852_ABILITY_EFFECT_5246 =
    "Там'Грарр кричит на ближайших врагов, заставляя их в страхе бежать в течение 8 секунд."
    IJ_DB_DUNGEON_SV_BOSS_80852_ABILITY_NAME_22859 = "Смертельный раскол"
    IJ_DB_DUNGEON_SV_BOSS_80852_ABILITY_EFFECT_22859 =
    "Там'Грарр наносит своей цели тяжелый урон и оставляет ее раненой, снижая эффективность любого исцеления на 50% на 5 секунд."
    IJ_DB_DUNGEON_SV_BOSS_80852_ABILITY_NAME_22857 = "Возмездие"
    IJ_DB_DUNGEON_SV_BOSS_80852_ABILITY_EFFECT_22857 =
    "Там'Грарр контратакует любого врага, нанесшего ему удар в ближнем бою, в течение 15 секунд. ||н||  ||н|| Атаки ближнего боя сзади не могут быть контратакованы."
    IJ_DB_DUNGEON_SV_BOSS_NAME_80850 = "Черная невеста"
    IJ_DB_DUNGEON_SV_BOSS_STORY_80850 =
    "Черная невеста — трагическая фигура, связанная непреодолимой любовью к Дамиану. Она нападает на любого, кто приближается, считая их осквернителями ее преданности, и говорит о своей любви к Потрошителю даже после смерти."
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_NAME_16867 = "Проклятие банши"
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_EFFECT_16867 =
    "Черная Невеста проклинает ближайших врагов, снижая их вероятность попадания на 10% на 12 секунд."
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_NAME_16565 = "Банши Вой"
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_EFFECT_16565 =
    "Черная Невеста стонет от боли, нанося противнику теневой урон."
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_NAME_17244 = "Владеть"
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_EFFECT_17244 =
    "Черная Невеста берет под свой контроль одного из своих врагов и начинает атаковать его союзников! ||н||  ||н|| Нанесение достаточного урона одержимому игроку освободит его от невесты!"
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_NAME_18327 = "Тишина"
    IJ_DB_DUNGEON_SV_BOSS_80850_ABILITY_EFFECT_18327 =
    "Черная невеста заставляет замолчать всех врагов в радиусе 10 метров, не позволяя им произносить заклинания в течение 10 секунд."
    IJ_DB_DUNGEON_SV_BOSS_NAME_80854 = "Дамиан"
    IJ_DB_DUNGEON_SV_BOSS_STORY_80854 =
    "Дамиан, также известный как Потрошитель, — смертоносный и неуловимый убийца, нападающий из тени. Он наслаждается боем, с безжалостной точностью охотится на тех, кто попадается ему на пути, и исчезает так же легко, как и появляется."
    IJ_DB_DUNGEON_SV_BOSS_80854_ABILITY_NAME_11700 = "Выкачивать жизнь"
    IJ_DB_DUNGEON_SV_BOSS_80854_ABILITY_EFFECT_11700 =
    "Дамиан высасывает жизнь из врага, передавая себе 70 единиц здоровья каждую секунду в течение 5 секунд."
    IJ_DB_DUNGEON_SV_BOSS_80854_ABILITY_NAME_11668 = "Приносить в жертву"
    IJ_DB_DUNGEON_SV_BOSS_80854_ABILITY_EFFECT_11668 =
    "Дамиан сжигает врага, сжигая его, нанося 258 ед. урона от огня и дополнительно 485 ед. урона от огня в течение 15 секунд."
    IJ_DB_DUNGEON_SV_BOSS_80854_ABILITY_NAME_1856 = "Исчезновение"
    IJ_DB_DUNGEON_SV_BOSS_80854_ABILITY_EFFECT_1856 = "Дамиан исчезает, устраивая засаду врагу, когда появляется снова."
    IJ_DB_DUNGEON_SV_BOSS_NAME_80851 = "Волкан Жестокий Клинок"
    IJ_DB_DUNGEON_SV_BOSS_STORY_80851 =
    "Волкан Жестокий Клинок — член клана Пылающего Клинка. Он сражается со смертоносным мастерством, стремясь к свободе и мести всем, кто противостоит ему."
    IJ_DB_DUNGEON_SV_BOSS_80851_ABILITY_NAME_9256 = "Глубокий сон"
    IJ_DB_DUNGEON_SV_BOSS_80851_ABILITY_EFFECT_9256 =
    "Волкан усыпляет ближайших врагов на 10 секунд. ||н||  ||н|| Любой нанесенный ущерб пробудит их."
    IJ_DB_DUNGEON_SV_BOSS_880851_ABILITY_NAME_15398 = "Психический крик"
    IJ_DB_DUNGEON_SV_BOSS_80851_ABILITY_EFFECT_15398 =
    "Волкан издает психический крик, заставляя врага застыть от страха на 8 секунд."
    IJ_DB_DUNGEON_SV_BOSS_880851_ABILITY_NAME_20741 = "Залп теневых стрел"
    IJ_DB_DUNGEON_SV_BOSS_80851_ABILITY_EFFECT_20741 =
    "Волкан бросает снаряды темной магии, нанося 255 ед. урона от темной магии каждому врагу в радиусе 30 м."
    IJ_DB_DUNGEON_SV_BOSS_880851_ABILITY_NAME_20603 = "Теневой шок"
    IJ_DB_DUNGEON_SV_BOSS_80851_ABILITY_EFFECT_20603 =
    "Волкан хлещет врагов в радиусе 20 метров темной магией, нанося каждому из них 740 теневого урона."
    IJ_DB_DUNGEON_SV_BOSS_NAME_93107 = "Арк'Тирас"
    IJ_DB_DUNGEON_SV_BOSS_STORY_93107 =
    "Арк'Тирас — мощный и разумный магический кристалл, запертый глубоко в Хранилище Штормграда. Его нестабильная энергия свела стражников с ума и превратила Убежище в лабиринт безумия."

    -- Deadmines
    IJ_DB_DUNGEON_DEADMINES_NAME = "Мертвые копи"
    IJ_DB_DUNGEON_DEADMINES_STORY =
    "Когда-то величайший центр добычи золота на землях людей, Мертвые копи были заброшены, когда Орда разрушила город Штормград во время Первой войны. Теперь Братство Справедливости обосновалось и превратило темные туннели в свое личное убежище. Ходят слухи, что воры наняли умных гоблинов, чтобы они помогли им построить на дне шахт что-то ужасное, но что это может быть, пока неизвестно. Ходят слухи, что путь в Мертвые копи лежит через тихую, скромную деревню Мунбрук."

    -- Deadmines Bosses
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_61961 = "Джаред Восс"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_61961 =
    "Джаред Восс — сын Уильяма Восса, известного алхимика, чей магазин и дом были сожжены во время Штормграда и так и не восстановлены, в результате чего его семья осталась без крова и ожесточена по отношению к ответственной за это знати. Джаред, который перед смертью своего отца был учеником каменщиков, унаследовал как его алхимические таланты, так и жгучую обиду."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_644 = "Рак'Зор"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_644 =
    "Как главный бригадир Мертвых копей Братства Справедливости, Рак'Зор контролирует и «мотивирует» рабочих. Его методы хоть и нетрадиционны, но весьма эффективны."
    IJ_DB_DUNGEON_DEADMINES_BOSS_644_ABILITY_NAME_6304 = "Рак'Зорский удар"
    IJ_DB_DUNGEON_DEADMINES_BOSS_644_ABILITY_EFFECT_6304 =
    "Рак'Зор бьет врага, нанося ему от 64 до 86 физического урона и оглушая его на 3 секунды."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_3586 = "Майнер Джонсон"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_3586 =
    "Неуловимый шахтер, редко встречающийся среди населения Мертвых Копей. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_DEADMINES_BOSS_3586_ABILITY_NAME_6016 = "Пирс Армор"
    IJ_DB_DUNGEON_DEADMINES_BOSS_3586_ABILITY_EFFECT_6016 =
    "Шахтер Джонсон бросает кирку в противника, пробивая его броню и снижая ее броню на 10% на 10 секунд."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_643 = "Снид"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_643 =
    "Снид был нанят лесорубом из-за его безжалостной эффективности. Его цель проста: построить джаггернаут как можно дешевле. Используя измельчитель, который он построил сам, чтобы руководить производством, он достигает ужасающе быстрых результатов."
    IJ_DB_DUNGEON_DEADMINES_BOSS_643_ABILITY_NAME_6713 = "Разоружение"
    IJ_DB_DUNGEON_DEADMINES_BOSS_643_ABILITY_EFFECT_6713 =
    "Снид обезоруживает своего врага, заставляя его прекратить использование оружия на 5 секунд."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_1763 = "Гилнид"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_1763 =
    "Глинид — искусный инженер и главный плавильный завод Братства Справедливости. Он следит за тем, чтобы джаггернаут был загружен достаточным количеством пушек и боеприпасов, и не допускает перерывов, пока работа не будет завершена."
    IJ_DB_DUNGEON_DEADMINES_BOSS_1763_ABILITY_NAME_5213 = "Расплавленный металл"
    IJ_DB_DUNGEON_DEADMINES_BOSS_1763_ABILITY_EFFECT_5213 =
    "Глинид бросает во врага расплавленный металл, нанося огненный урон каждые 3 секунды, увеличивая время между атаками на 54% и уменьшая его движение на 50% на 15 секунд."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_61963 = "Шедевральный комбайн"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_61963 =
    "Гоблинские механики Defias гордятся своим величайшим творением: Шедевральным комбайном. Построенный глубоко в их тайной мастерской, это лучший голем урожая, который они когда-либо создавали."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_646 = "Мистер Смайт"
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_NAME_6264 = "Ловкие рефлексы"
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_EFFECT_6264 =
    "Проворные рефлексы мистера Смайта позволяют ему увеличить шанс парирования на 75% на 8 секунд."
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_NAME_6435 = "Смайт Слэм"
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_EFFECT_6435 =
    "Мистер Смайт бьет своего врага, нанося 50 единиц физического урона и оглушая его на 3 секунды."
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_NAME_6432 = "Поразить топотом"
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_EFFECT_6432 =
    "Мистер Смайт топает по земле, оглушая всех врагов на 10 секунд."
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_NAME_3417 = "Трэш"
    IJ_DB_DUNGEON_DEADMINES_BOSS_646_ABILITY_EFFECT_3417 =
    "Мистер Смайт получает шанс провести две дополнительные атаки."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_647 = "Капитан Зеленокожий"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_647 =
    "Капитан джаггернаута, Зеленокожий родом из Пиратской бухты, где он раньше возглавлял флот пиратских судов."
    IJ_DB_DUNGEON_DEADMINES_BOSS_647_ABILITY_NAME_5208 = "Отравленный гарпун"
    IJ_DB_DUNGEON_DEADMINES_BOSS_647_ABILITY_EFFECT_5208 =
    "Капитан Зеленокожий пронзает своего врага отравленным гарпуном, нанося физический урон плюс 30, а затем дополнительно 45 урона от сил природы каждые 10 секунд в течение 1 минуты."
    IJ_DB_DUNGEON_DEADMINES_BOSS_647_ABILITY_NAME_845 = "Раскалывать"
    IJ_DB_DUNGEON_DEADMINES_BOSS_647_ABILITY_EFFECT_845 = "Капитан Зеленокожий рассекает всех врагов перед собой."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_639 = "Эдвин Ван Клиф"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_639 =
    "Ван Клиф, бывший лидер Гильдии каменщиков, из-за споров с Домом дворян покинул Штормград и создал Братство Справедливости. Затем Ван Клиф заявил, что Мертвые копи являются оперативной базой для строительства джаггернаута, который начнет его возмездие."
    IJ_DB_DUNGEON_DEADMINES_BOSS_639_ABILITY_NAME_3417 = "Мусор"
    IJ_DB_DUNGEON_DEADMINES_BOSS_639_ABILITY_EFFECT_3417 =
    "Эдвин Ван Клиф получает шанс провести две дополнительные атаки."
    IJ_DB_DUNGEON_DEADMINES_BOSS_639_ABILITY_NAME_5200 = "Союзники Ван Клифа"
    IJ_DB_DUNGEON_DEADMINES_BOSS_639_ABILITY_EFFECT_5200 =
    "Эдвин Ван Клиф взывает к своим союзникам, вызывая пару Черных Стражей Справедливости, чтобы они помогали ему во время битвы."
    IJ_DB_DUNGEON_DEADMINES_BOSS_NAME_645 = "печенье"
    IJ_DB_DUNGEON_DEADMINES_BOSS_STORY_645 =
    "Никто, кроме Эдвина Ван Клифа, не знает, как и почему Куки был назначен корабельным поваром. Однако для пиратов еда есть еда."
    IJ_DB_DUNGEON_DEADMINES_BOSS_645_ABILITY_NAME_6306 = "Кислотный всплеск"
    IJ_DB_DUNGEON_DEADMINES_BOSS_645_ABILITY_EFFECT_6306 =
    "Куки бросает на своих врагов немного кислотной жидкости, в результате чего все находящиеся поблизости получают урон от сил природы каждые 5 секунд в течение 30 секунд."
    IJ_DB_DUNGEON_DEADMINES_BOSS_645_ABILITY_NAME_5174 = "Кулинария печенья"
    IJ_DB_DUNGEON_DEADMINES_BOSS_645_ABILITY_EFFECT_5174 =
    "Куки съедает часть его еды, восстанавливая ему от 111 до 129 здоровья."

    -- BM
    IJ_DB_DUNGEON_BM_NAME = "Черная трясина"
    IJ_DB_DUNGEON_BM_STORY =
    "Глубоко в Пещерах Времени Бесконечная Рода Драконов стремится изменить ход истории, предотвращая открытие Темного Портала. Если им это удастся, орки никогда не прибудут в Азерот, и ключевые события, которые сформировали защиту мира от Пылающего Легиона, будут отменены. Чтобы сохранить историю, отважным искателям приключений придется отправиться на семнадцать лет назад в болота Черной топи. Там они должны защитить Стража Медива, пока он проводит свой ритуал, гарантируя, что темные врата откроются и нити судьбы останутся неразрывными."

    -- BM Links
    IJ_DB_DUNGEON_BM_LINK_BM = "Черная трясина"

    -- BM Bosses
    IJ_DB_DUNGEON_BM_BOSS_NAME_65113 = "Хронар"
    IJ_DB_DUNGEON_BM_BOSS_STORY_65113 =
    "Когда-то Хронар был гордым защитником временных путей, но нарушил священную клятву, данную Бронзовым драконам, и соединился с Бесконечностью. Теперь, превратившись в искаженную оболочку своего прежнего «я», он владеет «Изношенным временем копьем», оружием, которое он забрал у человеческого героя в прошлом конфликте, и неустанно работает, чтобы разрушить ту самую историю, которую он когда-то поклялся защищать."
    IJ_DB_DUNGEON_BM_BOSS_NAME_61575 = "Эпидаму"
    IJ_DB_DUNGEON_BM_BOSS_STORY_61575 =
    "По мере того как временные аномалии внутри трясины усиливаются, в конфликт втягиваются существа из разных времен. Эпидаму служит предвестником воли Бесконечного, используя свои искажающие реальность силы, чтобы выкачивать сущность болота и проявлять Порочный песок, который отравляет нарушенные временные рамки."
    IJ_DB_DUNGEON_BM_BOSS_NAME_61316 = "Дрейфующий аватар песка"
    IJ_DB_DUNGEON_BM_BOSS_STORY_61316 =
    "Сформированный из совокупности разрушенных возможностей, Дрейфующий Аватар Песка — это бессмысленная конструкция Бесконечной стаи драконов. Он действует как песочные часы гибели, олицетворяя Порченый песок, который вытекает из ран на временной шкале, сокрушая любого, кто пытается восстановить хронические повреждения."
    IJ_DB_DUNGEON_BM_BOSS_NAME_65116 = "Повелитель Времени Эпохронос"
    IJ_DB_DUNGEON_BM_BOSS_STORY_65116 =
    "Высокопоставленный стратег Бесконечной стаи драконов, Эпохронос руководит тактическим нападением на ритуал Медива. Он рассматривает линейный поток времени как клетку и стремится открыть будущее, в котором окончательное поражение Легиона будет предотвращено, полагая, что его «исправления» прошлого предназначены для общего блага Мультивселенной."
    IJ_DB_DUNGEON_BM_BOSS_NAME_65124 = "Моссхарт"
    IJ_DB_DUNGEON_BM_BOSS_STORY_65124 =
    "Древние болотные звери Черных Топей издавна были чувствительны к энергии земли. Моссхарт, когда-то мирный защитник болота, был доведен до состояния первобытной ярости временной радиацией, просачивающейся из Темного Портала. Теперь он набрасывается на все – бронзовое или бесконечное – что тревожит темные глубины его дома."
    IJ_DB_DUNGEON_BM_BOSS_NAME_65125 = "Антнорми"
    IJ_DB_DUNGEON_BM_BOSS_STORY_65125 =
    "Предательство Антнорми, бывшей соратницы бронзового дракона Керидорми, возможно, самое личное из всех. Убежденная, что прибытие орков — это трагедия, которую необходимо стереть, она встала на путь Бесконечности. Она является последним препятствием на южном пути времени, готовая убить своих бывших родственников, чтобы воплотить в жизнь свое видение «чистой» истории."
    IJ_DB_DUNGEON_BM_BOSS_NAME_65122 = "Гнилая пасть"
    IJ_DB_DUNGEON_BM_BOSS_STORY_65122 =
    "Огромный кроколиск с легендарным аппетитом, Гнилобрюх уже много лет пирует смещенными хрональными энергиями болота. Зверь стал неестественно большим и агрессивным, его пасть истекает энтропийной гнилью. Его мало заботит сохранение времени, рассматривая захватчиков Черных Топей только как столь необходимый праздник."

    -- SMGY
    IJ_DB_DUNGEON_SMGY_NAME = "Монастырь Алого ордена (Кладбище)"
    IJ_DB_DUNGEON_SMGY_STORY =
    "Монастырь когда-то был гордым бастионом жречества Лордерона — центром обучения и просвещения. С появлением нежити Плети во время Третьей войны мирный монастырь был превращен в оплот фанатичного Алого Ордена. Крестоносцы нетерпимы ко всем нечеловеческим расам, независимо от альянса или принадлежности. Они верят, что все без исключения посторонние являются потенциальными переносчиками чумы нежити и должны быть уничтожены."

    -- SMGY Bosses
    IJ_DB_DUNGEON_SMGY_BOSS_NAME_3983 = "Следователь Вишас"
    IJ_DB_DUNGEON_SMGY_BOSS_STORY_3983 =
    "Джеймс Вишас — ведущий следователь Алого ордена в монастыре Алого ордена. Ему нравится мучить любую захваченную нежить, и он очень гордится своей работой. Вишас известен своим безжалостным садизмом, жестоким опытом и высоким голосом."
    IJ_DB_DUNGEON_SMGY_BOSS_NAME_61972 = "Герцог Дредмур"
    IJ_DB_DUNGEON_SMGY_BOSS_NAME_6489 = "Железный хребет"
    IJ_DB_DUNGEON_SMGY_BOSS_STORY_6489 =
    "Неуловимая нежить, которую редко можно увидеть на кладбище монастыря. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_SMGY_BOSS_NAME_6490 = "Азшир Неспящий"
    IJ_DB_DUNGEON_SMGY_BOSS_STORY_6490 =
    "Неуловимый человеческий призрак, которого редко можно увидеть на кладбище монастыря. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_SMGY_BOSS_NAME_6488 = "Падший чемпион"
    IJ_DB_DUNGEON_SMGY_BOSS_STORY_6488 =
    "Неуловимая нежить, которую редко можно увидеть на кладбище монастыря. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_SMGY_BOSS_NAME_4543 = "Маг крови Талнос"
    IJ_DB_DUNGEON_SMGY_BOSS_STORY_4543 =
    "Талнос заслужил репутацию в Алом Крестовом походе благодаря жестоким методам пыток, которые он использовал для «очищения» новобранцев. В конце концов маг-садист заразился чумой нежити и превратился в грозное скелетное существо. Мстительный Талнос бродил по монастырскому кладбищу, командуя призраками и зомбированными существами, которые нападали на любого, кто вторгается в его нечестивые владения."

    -- SMLIB
    IJ_DB_DUNGEON_SMLIB_NAME = "Монастырь Алого ордена (библиотека)"
    IJ_DB_DUNGEON_SMLIB_STORY =
    "Монастырь когда-то был гордым бастионом жречества Лордерона — центром обучения и просвещения. С появлением нежити Плети во время Третьей войны мирный монастырь был превращен в оплот фанатичного Алого Ордена. Крестоносцы нетерпимы ко всем нечеловеческим расам, независимо от альянса или принадлежности. Они верят, что все без исключения посторонние являются потенциальными переносчиками чумы нежити и должны быть уничтожены."

    -- SMLIB Bosses
    IJ_DB_DUNGEON_SMLIB_BOSS_NAME_3974 = "Псарь Локси"
    IJ_DB_DUNGEON_SMLIB_BOSS_STORY_3974 =
    "Повелитель псов Локси — один из четырех лидеров Монастыря Алого ордена и капитан, отвечающий за дрессировку гончих, которых Алый Орден использует для выслеживания своих врагов. Локси командует верностью грозных собак, которые могут разорвать свою жертву на части за считанные минуты."
    IJ_DB_DUNGEON_SMLIB_BOSS_NAME_61983 = "Брат Вистан"
    IJ_DB_DUNGEON_SMLIB_BOSS_STORY_61983 =
    "Брат Вистан служит привратником монастырских архивов, фанатично защищая от внешнего мира «еретические» объекты, захваченные Крестовым походом. Среди его коллекции есть ториевый сервопривод, сложное инженерное произведение, которое он считает оскорблением Света. В то время как многие маги, такие как Элиас, покинули орден после того, как стали свидетелями погружения элиты в безумие и некромантию, Вистан остается стойким щитом, гарантирующим, что никакое «неестественное» влияние не покинет стены Библиотеки."
    IJ_DB_DUNGEON_SMLIB_BOSS_NAME_6487 = "Чародей Доан"
    IJ_DB_DUNGEON_SMLIB_BOSS_STORY_6487 =
    "Доан выступает хранителем библиотеки Монастыря Алого ордена; хранитель тайны, которому, по слухам, Алый Крестовый Поход не доверяет. Тем не менее, он действительно является доверенным лицом Крестового Похода, хранящим жизненно важный ключ, открывающий доступ к операциям Алого ордена в Чумных землях. Чародей Доан считает, что тайная магия — единственный способ избавить Лордерон от Плети."

    -- SMARM
    IJ_DB_DUNGEON_SMARM_NAME = "Монастырь Алого ордена (Оружейная палата)"
    IJ_DB_DUNGEON_SMARM_STORY =
    "Монастырь когда-то был гордым бастионом жречества Лордерона — центром обучения и просвещения. С появлением нежити Плети во время Третьей войны мирный монастырь был превращен в оплот фанатичного Алого Ордена. Крестоносцы нетерпимы ко всем нечеловеческим расам, независимо от альянса или принадлежности. Они верят, что все без исключения посторонние являются потенциальными переносчиками чумы нежити и должны быть уничтожены."

    -- SMARM Bosses
    IJ_DB_DUNGEON_SMARM_BOSS_NAME_61982 = "Интендант Оружейной палаты Дагхельм"
    IJ_DB_DUNGEON_SMARM_BOSS_STORY_61982 =
    "Будучи многообещающим учеником мастера-кузнеца Бэзила Фрая, Дагелм решил остаться в Монастыре, когда пришла Плеть, а его наставник сбежал в грязь Подгорода. Годы изоляции и фанатизма превратили его в психотического фанатика, одержимого ковкой доспехов в «благословениях» Света. Он до сих пор хранит дневник своего наставника на слитках Световой кузни, отказываясь расстаться с драгоценными записями, хотя Крестовый поход, которому он служит, разрушается вокруг него."
    IJ_DB_DUNGEON_SMARM_BOSS_NAME_3975 = "Ирод"
    IJ_DB_DUNGEON_SMARM_BOSS_STORY_3975 =
    "Ирод — один из четырех лидеров Алого ордена в Монастыре Алого ордена. Чемпион Алого Ордена, он известен своей жестокой репутацией."

    -- SMCATH
    IJ_DB_DUNGEON_SMCATH_NAME = "Монастырь Алого ордена (собор)"
    IJ_DB_DUNGEON_SMCATH_STORY =
    "Монастырь когда-то был гордым бастионом жречества Лордерона — центром обучения и просвещения. С появлением нежити Плети во время Третьей войны мирный монастырь был превращен в оплот фанатичного Алого Ордена. Крестоносцы нетерпимы ко всем нечеловеческим расам, независимо от альянса или принадлежности. Они верят, что все без исключения посторонние являются потенциальными переносчиками чумы нежити и должны быть уничтожены."

    -- SMCATH Bosses
    IJ_DB_DUNGEON_SMCATH_BOSS_NAME_4542 = "Верховный инквизитор Фэрбенкс"
    IJ_DB_DUNGEON_SMCATH_BOSS_STORY_4542 =
    "Когда-то он был священником и членом Рыцарей Серебряной Длани, ближайшим советником Верховного лорда Могрейна, а также бывшим Верховным инквизитором Алого ордена. Казненный крестоносцами за кощунственные обвинения в адрес Сайдана Датрохана и Рено Могрейна, он в конце концов стал нежитью."
    IJ_DB_DUNGEON_SMCATH_BOSS_NAME_3976 = "Командир Алого ордена Могрейн"
    IJ_DB_DUNGEON_SMCATH_BOSS_STORY_3976 =
    "В юности Рено был членом рыцарей Серебряной Длани и сыном их лидера, верховного лорда Александроса Могрейна. Управляемый Бальназаром через одержимый труп Сайдана Датрохана и завидуя вниманию, уделяемому его брату Дариону Могрейну, Рено принял предложение Великого крестоносца и повел своего отца в засаду, прежде чем убить его с помощью Испепелителя. Как и было обещано, Рено стал Командором Алого ордена Монастыря Алого ордена."
    IJ_DB_DUNGEON_SMCATH_BOSS_NAME_3977 = "Верховный инквизитор Вайтмейн"
    IJ_DB_DUNGEON_SMCATH_BOSS_STORY_3977 =
    "Салли Вайтмейн — жрица Света и Верховный инквизитор Алого ордена. Она руководит их деятельностью из Собора Алого монастыря."

    -- ZF
    IJ_DB_DUNGEON_ZF_NAME = "Зул'Фаррак"
    IJ_DB_DUNGEON_ZF_STORY =
    "Зул'Фаррак когда-то был сияющей жемчужиной Танариса, которого яростно защищало хитрое племя Песчаной Ярости. Несмотря на упорство троллей, эта изолированная группа на протяжении всей истории была вынуждена отказаться от большей части своей территории. Теперь, похоже, жители Зул'Фаррака создают ужасающую армию троллей-нежити, чтобы завоевать окружающий регион. Другие тревожные слухи рассказывают о древнем существе, спящем в городе, которое, если его разбудить, обрушит на Танарис дождь смерти и разрушений."

    -- ZF Bosses
    IJ_DB_DUNGEON_ZF_BOSS_NAME_10082 = "Зериллис"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_10082 =
    "Неуловимый тролль, которого редко можно увидеть в Зул'Фарраке. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_7272 = "Тека Мученица"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_7272 =
    "Давным-давно мученик Тека был убит в жестокой войне между киражами и троллями. Зул'Фаррак все еще стоит благодаря своей храброй жертве. Даже после смерти он продолжает бдить над своим любимым городом, и говорят, что десятки воинов-инсектоидов, убивших его, были прокляты жить как безмозглые скарабеи, бегущие рядом с мучеником."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_8127 = "Анту'сул"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_8127 =
    "Анту'сул предпочитает своих сул'литузских василисков сильными и безжалостными. Он относится к этим чешуйчатым зверям как к членам своей семьи и, как известно, убивает любого, даже собратьев-троллей, кто причиняет вред его драгоценным детям. Вместо того, чтобы похоронить своих противников должным образом, Анту'сул позволяет василискам полакомиться каждым, кто осмелится переступить ему дорогу."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_7271 = "Знахарь Зум'ра"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_7271 =
    "Могущественный лоа Бвонсамди наблюдает за духами троллей Черного Копья, но многим павшим членам племени Песчаной Ярости после смерти не предоставляется такой защиты. Эти замученные духи подчиняются Зум'ре, жестокому знахарю, который использует свою темную магию, чтобы заставить мертвецов города выполнять бесконечную службу."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_7275 = "Жрец теней Сезз'зиз"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_7275 =
    "Некрум Гутчевер таинственным образом прожил намного больше своей естественной жизни, но его разлагающееся тело остается достаточно сильным, чтобы помочь Сезз'зизу. Вместе эти два тролля собрали жертвы мифическому зверю Газ'рилле, дремлющему в самом сердце города. Многие последователи троллей с нетерпением ждут пробуждения ужасающего существа и сделают все, чтобы довести ритуал до конца."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_7267 = "Вождь Укорз Песчаный Скальп"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_7267 =
    "Вождь Укорз Песчаный Скальп одержим идеей вернуть своему племени былую славу. Он вырос на историях о временах, когда тролли господствовали на своих древних землях без вмешательства гоблинов, гномов, пиратов, огров и других иностранных нарушителей. Песчаный Скальп призвал своего верного товарища Руузлу помочь ему начать новую главу в истории Песчаной Ярости единственным способом, который знает их племя: быстрым и ослепляющим насилием."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_7273 = "Газ'рилла"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_7273 =
    "Легенда гласит, что Газ'рилла была обожаемым любимцем Древних Богов или даже самостоятельным полубогом. Какова бы ни была правда, тролли Песчаной Ярости поклонялись этой чудовищной гидре на протяжении тысячелетий. Всегда опасаясь ледяного гнева зверя, тролли разбудят Газ'риллу только тогда, когда у них будет много жертв, чтобы утолить голод хищного существа."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_62495 = "Зельджеб Древний"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_62495 =
    "Хотя вождь Укорз Песчаный Скальп когда-то был многообещающим лидером, чей разум в конечном итоге был искажен темной магией, Зель'джеб представляет старую, затянувшуюся тень племени Песчаной Ярости. Этот древний тролль служит мрачным напоминанием о магии, которая положила начало коррупции руководства города, помогая разжечь жестокий и холодный характер, который теперь определяет внутреннее святилище вождя. Пока пески Зул'Фаррака движутся, Зель'джеб стоит рядом с самыми фанатичными воинами племени, гарантируя, что наследие их искажённой силы не унесётся просто так, как песок по дюнам."
    IJ_DB_DUNGEON_ZF_BOSS_NAME_62498 = "Фарраки Арена"
    IJ_DB_DUNGEON_ZF_BOSS_STORY_62498 =
    "Арена Фарраки — известное поле боя, куда съезжаются тролли со всего города Зул'Фаррак и соревнуются в кровавых смертельных поединках."

    -- ST
    IJ_DB_DUNGEON_ST_NAME = "Храм Атал'Хаккара"
    IJ_DB_DUNGEON_ST_STORY =
    "Тысячи лет назад империя Гурубаши была ввергнута в гражданскую войну могущественной сектой жрецов Атал'ай, которая стремилась призвать в Азерот аватар своего бога крови, Хаккара Свежевателя Душ. Люди Гурубаши сослали Атал'ай в Болото Печали, где жрецы построили Храм Атал'Хаккара. Изера, аспект рода зеленых драконов, затопила храм под болотом и назначила стражей, чтобы гарантировать, что ритуалы призыва никогда больше не будут проводиться."

    -- ST Bosses
    IJ_DB_DUNGEON_ST_BOSS_NAME_8580 = "Атал'аларион"
    IJ_DB_DUNGEON_ST_BOSS_STORY_8580 =
    "Атал'аларион — поклявшийся защитник идола, найденного на самом нижнем уровне храма."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5708 = "Порождение Хаккара"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5708 =
    "Одно из многих порождений Хаккара, бродящее по залам затонувшего храма..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5713 = "Гашер"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5713 = "Один из шести троллей-защитников, не дающих сновидцу спать..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5717 = "Мижан"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5717 = "Один из шести троллей-защитников, не дающих сновидцу спать..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5712 = "Золо"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5712 = "Один из шести троллей-защитников, не дающих сновидцу спать..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5716 = "Зул'Лор"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5716 = "Один из шести троллей-защитников, не дающих сновидцу спать..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5715 = "Хукку"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5715 = "Один из шести троллей-защитников, не дающих сновидцу спать..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5714 = "Лоро"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5714 = "Один из шести троллей-защитников, не дающих сновидцу спать..."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5710 = "Джаммалан Пророк"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5710 =
    "Джаммал'ан - нынешний лидер Атал'ай, экстремистской секты священников, фанатично поклоняющихся Хаккару. Находясь в глубокой медитации, Джаммал'ан получил инструкции о том, как воскресить Хаккара, используя кровь его врагов-драконов, зеленых драконов. Джаммал'ан и его телохранитель-нежить Огом Несчастный готовы противостоять любому, кто помешает возвращению Хаккара, хотя действия пророка могут обрушить на Азерот еще более ужасную силу: Изумрудный Кошмар."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5721 = "Коса снов"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5721 =
    "Один из четырех драконов под непосредственным командованием Эраникуса Мечтателя. Они наблюдают за ним и не позволяют любому потенциальному злоумышленнику разбудить его ото сна."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5720 = "Ткач"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5720 =
    "Один из четырех драконов под непосредственным командованием Эраникуса Мечтателя. Они наблюдают за ним и не позволяют любому потенциальному злоумышленнику разбудить его ото сна."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5719 = "Морфаз"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5719 =
    "Один из четырех драконов под непосредственным командованием Эраникуса Мечтателя. Они наблюдают за ним и не позволяют любому потенциальному злоумышленнику разбудить его ото сна."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5722 = "Хаззас"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5722 =
    "Один из четырех драконов под непосредственным командованием Эраникуса Мечтателя. Они наблюдают за ним и не позволяют любому потенциальному злоумышленнику разбудить его ото сна."
    IJ_DB_DUNGEON_ST_BOSS_NAME_5709 = "Тень Эраникуса"
    IJ_DB_DUNGEON_ST_BOSS_STORY_5709 =
    "Эраникус, бывший супруг Изеры Мечтательницы, был послан охранять руины Атал'Хаккара и предотвращать появление Хаккара. Оказавшись внутри храма, он и его свита были развращены темными силами, и он стал тенью, зажатой между сферами Изумрудного сна и физическим планом. Несмотря на свою порчу, Эраникус все еще может использовать свои силы зеленого дракона, чтобы извергать едкую кислоту на своих врагов или погружать их в глубокий сон."
    IJ_DB_DUNGEON_ST_BOSS_NAME_8443 = "Аватар Хаккара"
    IJ_DB_DUNGEON_ST_BOSS_STORY_8443 =
    "Хаккар был известен тем, что требовал жертвоприношений от своих последователей. Много тысячелетий назад он поручил Атал'ай принести этого аватара, используя кровь, ритуально выжатую из живых жертв, чтобы накормить его. Жрецы Атал'ай теперь стремятся воскресить аватар Хаккара с помощью модифицированной версии этого ритуала, который включает в себя принесение в жертву зеленых драконов. Если Атал'ай добьются успеха, возрождение аватара Хаккара может означать гибель Азерота."

    -- BFD
    IJ_DB_DUNGEON_BFD_NAME = "Непроглядная Пучина"
    IJ_DB_DUNGEON_BFD_STORY =
    "Считалось, что Непроглядная Пучина, когда-то посвященная богине ночных эльфов Элуне, была разрушена во время Раскола и затеряна под океаном. Тысячелетия спустя члены культа Сумеречного Молота были привлечены в храм шепотом и кошмарными снами. Принеся в жертву бесчисленное количество невинных, культ был вознагражден новой задачей: защитить одно из самых любимых созданий Древних Богов, домашнее животное, которое все еще нуждается в заботе, прежде чем оно сможет обрушить свои темные силы на мир."

    -- BFD Bosses
    IJ_DB_DUNGEON_BFD_BOSS_NAME_4887 = "Гаму-ра"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_4887 =
    "Когда прибыл культ Сумеречного Молота, его последователи разбудили и заключили в тюрьму одно из последних мирных существ, живших в храме Элуны. Культ с удовольствием мучил гигантскую черепаху в течение многих лет, сдирая с нее кожу и разум, пока она не впала в безумие. Назвав зверя Гаму-Ра, культисты научили его атаковать чужаков и защищать святилище Древних Богов."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_4831 = "Леди Саревесс"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_4831 =
    "Сумеречный Молот предоставил леди Саревесс ее собственную бухту в Непроглядной Пучине, постоянно принося ей новые жертвы. Культисты надеются, что ее ритуалы и исследования приведут к магической защите, которая позволит им поклоняться ужасающей гидре в глубине глубин, не опасаясь стать его следующей едой."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_6243 = "Гелихаст"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_6243 =
    "Древние Боги позвали, и Гелихаст ответил, ворвавшись в Непроглядную Пучину и убив почти дюжину застигнутых врасплох культистов Сумеречного Молота своими парными мечами. Впечатленный его свирепостью и жестокостью, культ позволил ему остаться, и он построил свой собственный храм, чтобы приносить жертвы и получать благословения от зловещего присутствия в руинах храма."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_12902 = "Лоргус Джетт"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_12902 =
    "Таинственный член Сумеречного Молота, который, как говорят, обладает шаманскими способностями, несмотря на то, что он человек. По слухам, он был членом Рыцаря Серебряной Длани, прежде чем дезертировать и присоединиться к Сумеречному Молоту."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_62530 = "Велтелакс Осквернитель"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_62530 = "Древний сатир, скрывающийся в древнем храме Элуны."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_4830 = "Старый Серракис"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_4830 =
    "Многие существа, плававшие под руинами Лунного святилища, были убиты ради еды после того, как там поселился культ Сумеречного Молота, но самую большую молотилку в воде оказалось невозможно поймать, и те, кто упорствовал в охоте на нее, неизбежно погибли при попытке."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_4832 = "Сумеречный Лорд Келрис"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_4832 =
    "Когда культисты нашли странное трехголовое существо в недрах Непроглядной Пучины, Сумеречный Лорд Келрис был убежден, что гидра была вестником возвращения Древних Богов в Азерот... и его билетом в бессмертие. Келрис лично наблюдает за ростом монстра, даже кормя его своими подданными, чтобы утолить его дикий голод."
    IJ_DB_DUNGEON_BFD_BOSS_NAME_4829 = "Аку'май"
    IJ_DB_DUNGEON_BFD_BOSS_STORY_4829 =
    "Аку'май, древнее зло, несет в себе небольшую долю силы Древних Богов. Эту трехголовую гидру очень боятся из-за ее бессмысленной дикости и ненасытной жажды живой плоти, но Сумеречный Молот поклоняется ей как божественному знаку того, что Древние Боги скоро вернутся."

    -- Gnomeregan
    IJ_DB_DUNGEON_GNOMEREGAN_NAME = "Гномреган"
    IJ_DB_DUNGEON_GNOMEREGAN_STORY =
    "Расположенное в Дун Мороге технологическое чудо, известное как Гномреган, на протяжении поколений было столицей гномов. Недавно враждебная раса троггов-мутантов заполонила несколько регионов Дун Морога, включая великий город гномов. В отчаянной попытке уничтожить вторгшихся троггов верховный механик Меггакрут приказал экстренно выпустить воздух из городских резервуаров с радиоактивными отходами. Несколько гномов искали убежища от переносимых по воздуху загрязняющих веществ, ожидая, пока трогги умрут или сбегут. К сожалению, хотя троггов и облучило токсическое нападение, их осада продолжалась, не ослабевая. Те гномы, которые не были убиты ядовитой утечкой, были вынуждены бежать, ища убежища в соседнем городе дварфов Стальгорне. Там верховный механик Меггакрут намеревался привлечь смельчаков, чтобы помочь своему народу вернуть свой любимый город. Ходят слухи, что некогда доверенный советник Меггакрута, механик Термоштепсель, предал свой народ, допустив вторжение. Теперь, когда его рассудок пошатнулся, Термоштепсель остается в Гномрегане, продвигая свои темные планы и выступая в роли нового техно-повелителя города."

    -- Gnomeregan Bosses
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_NAME_7361 = "Груббис"
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_STORY_7361 =
    "Радиоактивный газ, затопивший город, должен был разозлить троггов и убить гномов, и план Термоштепселя оказался чрезвычайно эффективным. Однако один трогг странно отреагировал на это вещество: Груббис вырос. И вырос. Это был побочный эффект, которого Сикко не ожидал, но он никогда не тратил впустую ценные (и опасные) ресурсы. Этот гигантский трогг теперь патрулирует туннели Гномрегана. Его верный питомец-василиск Чомпер помогает Груббису выявлять утечки газа, вкусные грибы и даже более вкусных злоумышленников."
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_NAME_7079 = "Вязкие осадки"
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_STORY_7079 =
    "Некогда прочные и элегантно сложные водные пути Гномрегана теперь превратились в облученный беспорядок, наполненный токсичной слизью. Одинокий элементаль воды, обитавший в водоносном горизонте гномов, оказался в ловушке загрязнения, и загрязнение исказило его чистую форму. В настоящее время он бродит по залам Гномрегана в гневе и агонии, жидкое воплощение отвратительного яда предательства Термоштепселя."
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_NAME_6235 = "Электрошокер 6000"
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_STORY_6235 =
    "Мекгинир Термоштепсель не терпеливый гном. Вместо того чтобы подвергать свои изобретения серии испытаний для определения их безопасности и эффективности, он срочно запускает их в эксплуатацию и переходит к следующему проекту. Electrocutioner 6000 был его первой попыткой использовать электричество в качестве оружия с помощью сверхзаряженного механотанка. Лейтенант Том «Шипящие Штаны» Крэнкл, единственный солдат, который выжил, пилотируя Электрошокера, теперь стал чем-то вроде героя среди прокаженных гномов."
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_NAME_6229 = "Разрушитель толпы 9-60"
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_STORY_6229 =
    "Во времена расцвета Гномрегана изобретатели соревновались за статус, противопоставляя свои творения друг другу. Мекгинженер Оглторп Обнотикус построил непобедимого робота, чем заслужил уважение при дворе высшего мастера. Сикко Термаштепсель украл чертежи Обнотикуса, а затем создал гигантскую версию машины. Он раскрыл свою подделку, и ужасающие результаты заставили правящий совет изгнать невиновного Обнотикуса. Crowd Pummeler 9-60 до сих пор остается одним из любимых (украденных) изобретений Thermaplugg."
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_NAME_6228 = "Посол Черного Железа"
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_STORY_6228 =
    "Никто не знает, почему посол дворфов Черного Железа был отправлен в павшую столицу Гномреган. Ходили слухи, что Чёрное Железо заключило сделку с Термоштепселем о том, чтобы направить троггов в Гномреган из их операций в Ульдамане, откуда произошли трогги."
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_NAME_7800 = "Инженер по термоштепселю"
    IJ_DB_DUNGEON_GNOMEREGAN_BOSS_STORY_7800 =
    "Убийца, предатель и самопровозглашенный король гномов, механинженер Сикко Термоштепсель правит радиоактивными залами Гномрегана с помощью неисправного железного кулака. Его подданные многочисленны, порочны и достаточно безумны, чтобы защитить своего безумного короля от любого вторжения из верхнего мира. Именно безумие Термоштепселя делает его таким опасным; он обладает хитростью разрушать все вокруг себя, не думая о собственной жизни. Есть причина, по которой его боятся даже монстры Гномрегана."

    -- Uldaman
    IJ_DB_DUNGEON_ULDA_NAME = "Ульдаман"
    IJ_DB_DUNGEON_ULDA_STORY =
    "Ульдаман — древнее хранилище Титанов, погребенное глубоко под землей с момента сотворения мира. Гномьи раскопки недавно проникли в этот забытый город, освободив первые неудачные творения Титанов: Троггов. Легенды гласят, что титаны создали троггов из камня. Когда они сочли эксперимент неудачным, Титаны заперли троггов и попытались снова, что привело к созданию расы гномов. Тайны создания гномов записаны на легендарных Дисках Норганнона — массивных артефактах Титанов, лежащих в самом низу древнего города. Недавно дворфы Черного Железа предприняли серию вторжений в Ульдаман, надеясь забрать диски для своего пламенного хозяина Рагнароса. Однако погребенный город защищают несколько стражей — гигантские конструкции из живого камня, сокрушающие любого незадачливого злоумышленника, которого они найдут. Сами Диски охраняет массивный и разумный Хранитель Камней по имени Архедас. Некоторые слухи даже предполагают, что предки гномов с каменной кожей, земляные, до сих пор обитают глубоко в потайных уголках города."

    -- Uldaman Bosses
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_6906 = "Потерянные гномы"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_6906 =
    "В поисках славы и, что более важно, богатства, три брата Эрик, Олаф и Бэйлог заключили контракт с Лигой исследователей, чтобы они проникли вглубь залов Ульдамана и расчистили путь для группы исследователей. Однако для этих трех гномов «расчистка пути», к сожалению, повлекла за собой «безнадежное заблудение в древнем лабиринте». Гордые гномы до конца борются за то, чтобы тайны Ульдамана и Лиги Исследователей не попали в руки Орды."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_6910 = "Ревелош"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_6910 =
    "Некоторые светила престижной Лиги исследователей Стальгорна выдвинули теорию о наследственной связи между своим народом и троггами и указали на накопление троггами артефактов из титанов как на отражение собственного благоговения гномов перед такими чудесными устройствами. Если это правда, то трогга, известного как Ревелош, можно считать троггским эквивалентом археолога, хотя любой искатель приключений с историческим складом ума, столкнувшийся с ним, был бы более склонен назвать его вором."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_7228 = "Иронайя"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_7228 =
    "Титаны не строили комплекс Ульдаман напрямую, а использовали различных слуг для создания его мегалитических залов. Пантеон поручил наблюдателю Иронайе наблюдать за строительством и обслуживанием Ульдамана, но со временем некогда внушающее трепет хранилище пришло в упадок. В камере с картами Иронайя провела тысячелетия в стазисе, анализируя первоначальный генеральный план, составленный Каз'горотом, и пытаясь найти способ восстановить первоначальную функциональность комплекса."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_7023 = "Обсидиановый страж"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_7023 =
    "Обсидиановый Страж отвечал за охрану секретов Ульдамана до тех пор, пока не подвергся воздействию неизвестной силы. Первоначально созданный из того же камня, что и залы самого Ульдамана, этот хранитель заменил большую часть своего тела темным стеклом, способным отражать заклинания. Что бы ни послужило причиной трансформации Обсидианового Стража, оно должно быть невероятно могущественным, поскольку изменить зачарованный камень титановой конструкции непросто."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_7206 = "Древний каменный хранитель"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_7206 =
    "Один из многих големов, которые обслуживали огромное хранилище титанов и управляли им, Древний Хранитель Камня был частью небольшой группы, которая служила посредником между наблюдателями, оставленными под контролем объекта, и их многочисленными слугами. Из-за порчи Обсидианового Стража Хранитель Древнего Камня стал последним в своем роде, выполняющим свой долг, защищая секреты титанов, насколько это возможно, до его неизбежного закрытия."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_7291 = "Галганн Огненный Молот"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_7291 =
    "В ответ на открытие Ульдамана дворфами Бронзобородов клан Черного Железа организовал вторжение в хранилище, чтобы не дать своим исконным врагам получить доступ к могущественным артефактам внутри. Галганн Огненный Молот, сенатор от города Кузница Теней, был отправлен наблюдать за продолжающимися раскопками Ульдамана, чтобы император мог использовать разрушительный потенциал артефактов против врагов Черного Железа."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_4854 = "Гримлок"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_4854 =
    "В обществе троггов самый большой, сильный и злобный трогг часто становится вождем, демонстрируя свою силу. Гримлок является сравнительно гением в том смысле, что он сохранил контроль над троггами Каменного Хранилища посредством запугивания и того, что можно было бы назвать грубой психологической войной. Обучив смертоносного василиска, Гримлок использует угрозу окаменения своим зверем, чтобы держать в узде потенциальных узурпаторов."
    IJ_DB_DUNGEON_ULDA_BOSS_NAME_2748 = "Архедас"
    IJ_DB_DUNGEON_ULDA_BOSS_STORY_2748 =
    "Глубоко внутри Ульдамана находится комната, содержащая одно из величайших сокровищ титанов, созданное самим Норганноном. Однако до сих пор ни одному исследователю не удалось получить доступ к реликвии, поскольку любая попытка сделать это активирует великого наблюдателя Архедаса, огромного стража, который легко уничтожает искателей сокровищ своими мощными атаками и настоящей армией слуг. Созданный из древнейшего и прочного камня, добытого из глубин Ульдамана, Архедас — враг столь же грозный, сколь и древний."

    -- DMN
    IJ_DB_DUNGEON_DMN_NAME = "Север Забытого Города"
    IJ_DB_DUNGEON_DMN_STORY =
    "Общины Гордока расположены на севере Забытого Города. Эта часть города была захвачена Гордоками, элитными членами клана огров Гордунни, и теперь является центром власти самого короля Гордока. Однако по традиции тот, кто убьет короля, станет новым королем Гордоком."

    -- DMN Bosses
    IJ_DB_DUNGEON_DMN_BOSS_NAME_14326 = "Страж Мол'дар"
    IJ_DB_DUNGEON_DMN_BOSS_STORY_14326 =
    "Мол'дар — ревностно преданный стражник огров Гордока. Он убежден, что король Гордок подарил ему пару зачарованных рукавиц, которые позволили ему шесть лет подряд становиться чемпионом своего народа по армрестлингу. По правде говоря, король Гордок выбросил мощные доспехи; Мол'дар просто нашел его первым."
    IJ_DB_DUNGEON_DMN_BOSS_NAME_14322 = "Стомпер Криг"
    IJ_DB_DUNGEON_DMN_BOSS_STORY_14322 =
    "Не раз скрывающиеся убийцы встречали свою гибель после того, как случайно потревожили кружку с элем Крига. Хотя он часто теряет сознание в нетрезвом состоянии на дежурстве, ничто не приводит огра в ярость берсерка быстрее, чем звук его драгоценного напитка, разбрызгиваемого на каменный пол."
    IJ_DB_DUNGEON_DMN_BOSS_NAME_14321 = "Страж Фенгус"
    IJ_DB_DUNGEON_DMN_BOSS_STORY_14321 =
    "С тех пор, как Чо'Раш Наблюдатель сказал ему, что ему суждено встретить товарища во время службы, Фенгус почти каждую минуту бодрствования проводил, патрулируя территорию Гордока."
    IJ_DB_DUNGEON_DMN_BOSS_NAME_14323 = "Стражник Слип'кик"
    IJ_DB_DUNGEON_DMN_BOSS_STORY_14323 =
    "Некоторые могут подумать, что Слип'кик просто осторожен, но он еще и ленив. Вместо того, чтобы напрямую бросить вызов королю Гордоку, Слип'кик возится с ловушками и старыми, сломанными магическими устройствами, надеясь в конечном итоге нанести решающий удар без грамма риска и капли пота."
    IJ_DB_DUNGEON_DMN_BOSS_NAME_14325 = "Капитан Кромкраш"
    IJ_DB_DUNGEON_DMN_BOSS_STORY_14325 =
    "Даже среди огров капитан Кромкраш печально известен своей неистовой яростью по отношению к любому, кто посмеет оскорбить его или короля Гордока. Он безжалостно подавляет инакомыслие, но еще меньше у него терпения к тем, кто продолжает распространять слухи о его бурном романе с гноллом, давным-давно."
    IJ_DB_DUNGEON_DMN_BOSS_NAME_11501 = "Король Гордок"
    IJ_DB_DUNGEON_DMN_BOSS_STORY_11501 =
    "Чтобы править ограми Гордока, нужно просто провозгласить себя королем... а затем уничтожить всех, кто не согласен. Король Гордок, тогда известный просто как Улрок, укрепил свою власть, убедив дюжину сильнейших воинов своего народа одновременно бросить вызов королю. В дикой схватке большинство участников были убиты или ранены, а клинок Улрока легко сразил выживших и утомленного битвой короля. По сей день огры Гордока приглушенно говорят о «Дне Крови»."

    -- DMW
    IJ_DB_DUNGEON_DMW_NAME = "Запад Забытого Города"
    IJ_DB_DUNGEON_DMW_STORY =
    "Столичные сады расположены на западе Забытого Города. Возможно, когда-то этот район был нетронутым городским парком, но теперь деревья стоят серые и увядшие, а разбитые улицы полны опасных древних людей."

    -- DMW Bosses
    IJ_DB_DUNGEON_DMW_BOSS_NAME_11489 = "Тендрис Искривленный лес"
    IJ_DB_DUNGEON_DMW_BOSS_STORY_11489 =
    "Тендрис Варпвуд был стойким защитником Элдре'Таласа, его сердце неразрывно связано с судьбой города. Когда Раскол разрушил землю, его решимость никогда не поколебалась, но по мере того, как порча просачивалась в руины в течение следующих 10 000 лет, она также заразила дух древнего."
    IJ_DB_DUNGEON_DMW_BOSS_NAME_11488 = "Иллианна Равеноак"
    IJ_DB_DUNGEON_DMW_BOSS_STORY_11488 =
    "Иллианна Равеноак вместе со своей верной спутницей Феррой когда-то была самым ценным охотником принца Тортелдрина, пока она не отказалась выполнить приказ своего лидера казнить своих друзей. В качестве наказания он убил Иллианну и ее медведя, но использовал свою демоническую силу, чтобы привязать их души к их телам, обрекая их оставаться в Забытом Городе в качестве защитников нежити."
    IJ_DB_DUNGEON_DMW_BOSS_NAME_11487 = "Магистр Календрис"
    IJ_DB_DUNGEON_DMW_BOSS_STORY_11487 =
    "Когда принц Тортелдрин потребовал убийства большинства своих подданных, его самым верным помощникам было поручено выполнить его волю. Магистр Календрис без колебаний убил многих ничего не подозревающих Шен'драларов, но один из обреченных эльфов смертельно ранил его во время разрушительной битвы. Несмотря на его кончину, дух Календриса все еще бродит по Забытому Городу как защитник правления Тортелдрина."
    IJ_DB_DUNGEON_DMW_BOSS_NAME_11467 = "Цу'зи"
    IJ_DB_DUNGEON_DMW_BOSS_STORY_11467 =
    "Неуловимый призрак ночного эльфа, редко встречающийся среди обитателей Столичных Садов. Говорят, что она обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ней..."
    IJ_DB_DUNGEON_DMW_BOSS_NAME_11496 = "Иммол'тар"
    IJ_DB_DUNGEON_DMW_BOSS_STORY_11496 =
    "В отчаянной попытке восстановить силу и бессмертие, которые они потеряли, когда Источник Вечности был разрушен, Шен'дралар призвали демона в западное крыло Забытого Города и захватили его силовым полем, позволив им использовать энергию ужаса Бездны для своих собственных заклинаний. Не имея возможности сопротивляться или даже двигаться в течение почти 10 000 лет, Иммол'тар мог только смотреть и ждать того дня, когда он сможет вырваться на свободу и разорвать плоть своих похитителей."
    IJ_DB_DUNGEON_DMW_BOSS_NAME_11486 = "Принц Тортелдрин"
    IJ_DB_DUNGEON_DMW_BOSS_STORY_11486 =
    "После разрушения Источника Вечности принц Тортелдрин сохранил контроль над выжившими Шен'драларами, заключив демона в руинах Элдре'Таласа и позволив своим подданным выкачивать его силу. Воздействие демонической силы исказило разум Тортелдрина, и когда существо дрогнуло, принц приказал убить многих своих вассалов, чтобы только он и его самые фанатичные последователи остались наслаждаться порочной энергией."

    -- DME
    IJ_DB_DUNGEON_DME_NAME = "Восток Забытого Города"
    IJ_DB_DUNGEON_DME_STORY =
    "Квартал Варпвуда расположен на востоке Забытого Города. Его захватил гнусный Альззин Дикообразный, сатир, который испортил Плод Плодородия так, что из него стали производить мерзкие осколки лозы Скверны. Альззин привлек к своему делу всевозможные испорченные растения, сатиров, магов и демонов. Весь район зарос сумасшедшей растительностью."

    -- DME Bosses
    IJ_DB_DUNGEON_DME_BOSS_NAME_14354 = "Пузилин"
    IJ_DB_DUNGEON_DME_BOSS_STORY_14354 =
    "Трусливый маленький бесенок, обманом заставляющий искателей приключений следовать за ним, только для того, чтобы наброситься на них, убивая их и крадя все имущество из их тел."
    IJ_DB_DUNGEON_DME_BOSS_NAME_11490 = "Зеврим Терновое Копыто"
    IJ_DB_DUNGEON_DME_BOSS_STORY_11490 =
    "Отчаявшись показать свою ценность Пылающему Легиону, Зеврим Терновое Копыто сказал своим хозяевам, что может поработить грозных древних, которые все еще бродили по Забытому Городу. Когда его собственной силы оказалось недостаточно, Торнхуф обратился к другим живым существам за дополнительной энергией, убивая их на своем жертвенном алтаре и собирая их сущность в их последние, мучительные минуты."
    IJ_DB_DUNGEON_DME_BOSS_NAME_13280 = "Гидроспаун"
    IJ_DB_DUNGEON_DME_BOSS_STORY_13280 =
    "Когда сатир Зеврим Терновое Копыто пытался контролировать элементалей в Забытом Городе, он сосредоточил свое внимание на Гидроотродье, которое спокойно обитало в пруду под его алтарем. Выполняя свои нечестивые жертвенные ритуалы, элементаль становился возбужденным и беспокойным, нанося удары по демоническим приспешникам Тернового Копыта. Шли годы, Торнхуф использовал энергию своих жертв, чтобы довести Гидроспауна до необузданной ярости, постепенно подчиняя его волю командам сатира."
    IJ_DB_DUNGEON_DME_BOSS_NAME_14327 = "Леттендрис"
    IJ_DB_DUNGEON_DME_BOSS_STORY_14327 =
    "Извращенная энергия Забытого Города привлекла Леттендрис издалека, дав ей надежду удовлетворить невыносимую тягу к тайной магии. Используя сухожилия и связки жертвенных жертв, она построила паутину, чтобы выкачивать порочную силу из восточного крыла. К своему удовольствию, она обнаружила, что устройство способно собрать огромные запасы подавляющей силы, достаточные, чтобы уничтожить всех ее врагов."
    IJ_DB_DUNGEON_DME_BOSS_NAME_11492 = "Альззин Дикообразный"

    -- BRD
    IJ_DB_DUNGEON_BRD_NAME = "Глубины Черной горы"
    IJ_DB_DUNGEON_BRD_STORY =
    "В тлеющих глубинах Черной горы обитают дворфы Черного Железа и их император Дагран Тауриссан. Как и его предшественники, он служит под железным правлением Рагнароса Повелителя Огня, беспощадного существа, призванного в мир много веков назад. Присутствие хаотических элементалей привлекло в горные владения культистов Сумеречного Молота. Вместе со слугами Рагнароса они подтолкнули гномов к все более разрушительным целям, которые вскоре могут означать гибель всего Азерота."

    -- BRD Bosses
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9018 = "Верховный следователь Герстан"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9018 =
    "Культист Сумеречного Молота Герстан всегда баловал себя прекрасными вещами: экзотической едой, красивой одеждой и инкрустированными драгоценными камнями орудиями пыток. День и ночь душераздирающие крики ее пленников эхом разносятся по печально известному изолятору клана Черного Железа. Герстан с гордостью называет этот ужасающий шум своей симфонией криков, и ей всегда хочется добавить к припеву еще один голос."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9025 = "Лорд Роккор"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9025 =
    "Лорд Роккор ненавидит интриги и предательства своих товарищей-огненных элементалей. Чтобы не служить вместе с себе подобными в Огненных Недрах, могучее существо намеренно разозлило Повелителя Огня. Рискованный гамбит Роккора оправдался: его изгнали из ядра и заставили в изоляции охранять Глубины Черной горы."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9319 = "Псарь Гребмар"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9319 =
    "Гончие Гребмара Флиберда — единственная семья, которую он когда-либо знал. Давным-давно осиротевший гном начал разводить собак в качестве компаньонов и сторожевых собак. Когда погонщик не патрулирует Глубины Черной горы со своими верными зверями, он часто угощает их лучшим элем Черного Железа, приготовленным Мрачным Обжорой."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9031 = "Кольцо Закона"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9031 =
    "За преступления, совершенные против дворфов Черного Железа, существует только одно наказание: смерть. Древняя традиция призывает виновных заплатить кровавую цену в Кольце Закона, сражаясь с дикими существами, собранными со всего Азерота. На сегодняшний день неизвестно, выжил ли кто-нибудь когда-либо в этом жестоком суровом испытании."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9024 = "Пиромант Лорегрен"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9024 =
    "Когда-то Лорегрейн был уважаемым членом Служителей Земли, но присоединился к культу Сумеречного Молота по причинам, которые остаются загадкой для его бывших союзников. В конце концов он отправился в Глубины Черной горы, где внезапно заинтересовался знаменитым архитектором Черного Железа Франклорном Форгерайтом. Цель его нынешней одержимости неясна, но Лорегрен остается верным своему культу и врагом всех, кто ему противостоит."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9041 = "Надзиратель Стилгисс"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9041 =
    "После многих лет преданности императору Тауриссану хитрому магу Стилгису было поручено защищать казну своего клана в Черном Хранилище. Близкий друг верного дварфа Псарь Гребмар отпраздновал это событие, подарив Стилгису одну из своих злобных собак — Верека. Маг нашел зверю хорошее применение, держа его при себе, чтобы отпугнуть потенциальных воров хранилища."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9476 = "Сторож Хватка Рока"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9476 =
    "Как страж Черного Хранилища, Хватка Рока очень серьёзно относится к своей профессии. Если бы искатели приключений попытались украсть содержимое хранилища, они наверняка встретили бы гнев дворфа Черного Железа..."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9056 = "Финеус Дарквир"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9056 =
    "Главный архитектор Финеус Дарквайр заслужил свой титул, выдавая идеи более одаренных каменщиков за свои собственные. Его высокомерие и интриги вызвали гнев его предшественника, Франклорна Форгерайта, из могилы. Призрак покойного главного архитектора пытается забрать свой невероятно мощный молот - Железный Фел - из Дарквира, прежде чем его можно будет использовать во вред."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9017 = "Лорд Огненный"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9017 =
    "Барон Геддон научил Огненного использовать свои разрушительные силы, но барон никогда не ожидал, что его протеже станет настолько смертоносно эффективным. Все больше опасаясь, что Огненный может узурпировать его, Геддон отправил пылающего элементаля из Огненных Недр охранять легендарную Черную Наковальню дворфов Черного Железа."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9016 = "Баел'Гар"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9016 =
    "Чудовищный расплавленный гигант Баел'Гар с грохотом движется по Шоссе Черного Железа — потрясающему шедевру гномьей инженерной мысли, высеченному в глубинах Черной горы. Рагнарос вытащил гиганта из сердца Огненных Просторов, чтобы тот охранял массивную запечатанную дверь на одном конце шоссе. Согласно легенде, только Повелитель Огня и самые высокопоставленные члены клана Черного Железа знают, что находится за таинственными вратами."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9033 = "Генерал Гневагорн"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9033 =
    "За долгие годы обучения генерал Ангерфордж стал знатоком дварфийской военной истории и тактики. Недавно он навлек на себя ярость императора Даграна Тауриссана, написав резкий трактат о неудачах своего клана в прошлых конфликтах. Если оставить в стороне эту политическую ошибку, Гневегорн по своей сути является Черным Железом. Он прольет кровь – и, если необходимо, умрет – чтобы защитить свой народ и своего императора."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_8983 = "Лорд големов Аргельмах"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_8983 =
    "Пожизненная одержимость Аргельмаха бессмертием побудила его создавать зачарованные конструкции по своему собственному образу. Ходят слухи, что он также баловался некоторой формой черной магии, которая позволит новым творениям повелителя големов действовать как сосуды для его духа, если его тело из плоти и крови будет уничтожено."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9537 = "Херли Черное Дыхание"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9537 =
    "Сказать, что Черное Дыхание — завсегдатай «Мрачного Обжоры», было бы преуменьшением. За более чем десять лет озорной пьяница покинул таверну только один раз, чтобы украсть сверхсекретный рецепт лагера Thunderbrew. Черное Дыхание иногда достаточно протрезвел, чтобы самому приготовить смесь, и он утверждает, что она дает невообразимую силу и смелость."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9543 = "Риббли Винтпагот"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9543 =
    "У Screwspigot есть дурная привычка брать деньги в долг и тратить их на схемы быстрого обогащения. Его последняя неудача — «Жевательный порох» Риббли — принесла ему место в списке преступников Бути-Бэй, барона Ревилгаза. С тех пор Скручпигот сбежал к Мрачному Обжоре, надеясь ускользнуть от охотников за головами, друзей и семьи, желающих нажиться на награде барона."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9502 = "Фаланга"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9502 =
    "До недавнего времени в «Мрачном обжоре» почти ежедневно бушевали пьяные драки. Бармен Плаггер Спаззринг сократил частоту подобных драк с помощью Фаланги, могучего голема-вышибалы, запрограммированного поддерживать порядок в таверне и уничтожать шумных посетителей с чрезвычайной силой."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9499 = "Плаггер Спаззринг"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9499 =
    "Говорят, в «Мрачном обжоре» все знают твое имя. Это чувство товарищества возникло благодаря упорному труду Спаззринга, прокаженного гнома, который искал новую жизнь в Глубинах Черной горы после падения Гномрегана. Несмотря на то, что в качестве колдуна он увлекался злом, он гордится своей работой бармена в таверне, следя за тем, чтобы кружки его посетителей никогда не иссякали."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9156 = "Посол Флэмлэш"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9156 =
    "За непоколебимое служение Рагнаросу Огнехлеш получил звание посла клана Черного Железа. Это развратное существо поначалу презирало своих союзников-гномов, но теперь стало уважать их склонность к разрушению. В знак солидарности Огненная Хлыст охраняет Зачарованную Палату, священное место, используемое гномами для усиления своего оружия."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_8923 = "Панзор Непобедимый"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_8923 =
    "Неуловимый голем, редко встречающийся среди населения Глубин Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9040 = "Семь"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9040 =
    "Несколько столетий назад тан-чародей Тауриссан и семь его самых могущественных союзников из Черного Железа случайно призвали Рагнароса в Азерот и обрекли весь свой клан на порабощение. Хотя Семеро погибли во время ритуала, их беспокойные души все еще обитают в Глубинах Черной горы, проклятые служить своему повелителю стихий и нынешнему правителю Черного Железа."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9938 = "Магмус"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9938 =
    "Посол Пламя Пламени поручил расплавленному гиганту Магмусу охранять тронный зал императора Даграна Тауриссана, но даже этот поступок не развеял опасения правителя Черного Железа. Всегда опасаясь убийц, император также предоставил Магмусу контроль над серией огнедышащих статуй возле своих королевских покоев."
    IJ_DB_DUNGEON_BRD_BOSS_NAME_9019 = "Император Дагран Тауриссан"
    IJ_DB_DUNGEON_BRD_BOSS_STORY_9019 =
    "Император Дагран Тауриссан правит вместе с принцессой Мойрой из конкурирующего клана Бронзобородов. Разгораются споры о том, околдовал ли император свою невесту или она добровольно присоединилась к нему. Какова бы ни была правда, продолжающееся присутствие Тауриссана не сулит ничего плохого для будущего его клана. Пока он жив, Чёрное Железо останется пешкой Рагнароса и страшной угрозой для королевств по всему Азероту."

    -- LBRS
    IJ_DB_DUNGEON_LBRS_NAME = "Нижняя часть Пика Черной горы"
    IJ_DB_DUNGEON_LBRS_STORY =
    "Эта внушительная крепость, высеченная в огненном ядре Черной горы, на протяжении веков олицетворяла мощь клана Черного Железа. Совсем недавно черный дракон Нефариан и его порождения захватили верхний шпиль крепости и развязали жестокую войну против гномов. С тех пор армии драконов объединились с вождем Рендом Черноруким и его ложной Ордой. Эти объединенные силы господствуют над шпилем, проводя ужасающие эксперименты, чтобы укрепить свои ряды, и одновременно планируют падение назойливого Черного Железа."

    -- LBRS Bosses
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9219 = "Мясник из Шипового Камня"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9219 =
    "Неуловимый огр, редко встречающийся среди населения Нижнего Пика Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9196 = "Верховный Лорд Омокк"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9196 =
    "Омокк правит ограми шпиля железной рукой. Многие подчиненные вызывали его на единоборство в надежде завоевать титул верховного лорда, но все они пали, не нанеся ни единого удара. Это загадочное явление привело к появлению слухов о том, что темная магия защищает Омокка."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9218 = "Боевой Лорд Шпильного Камня"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9218 =
    "Неуловимый огр, редко встречающийся среди населения Нижнего Пика Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9217 = "Лорд-маг из Шпильного Камня"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9217 =
    "Неуловимый огр, редко встречающийся среди населения Нижнего Пика Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9236 = "Теневой охотник Вос'гаджин"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9236 =
    "Вош'гаджин известна среди троллей своей красотой и психотическими наклонностями. Мастер искусства теневого охотника, она владеет грозными заклинаниями, проклятиями и исцеляющей магией."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9237 = "Военный мастер Вун"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9237 =
    "Во время Второй войны Вун возглавлял небольшие ударные группы, выполнявшие смелые миссии в самом сердце территории высших эльфов. Коварный тролль присоединился к ложной Орде, потому что хотел быть ее главным стратегом, а не потому, что верил в идеологию Чернорукого. Вун считает отколовшуюся фракцию проигравшим и получает удовольствие от преодоления непреодолимых препятствий."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9596 = "Баннок Гримакс"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9596 =
    "Неуловимый орк, редко встречающийся среди населения Нижнего Пика Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_10596 = "Мать Дымящаяся паутина"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_10596 =
    "Столетия назад дворфы Черного Железа ворвались в логово Матери Дымящей Паутины, выпустив огромного паукообразного в залы шпиля. С тех пор численность ее выводка продолжает увеличиваться настолько, что даже силы Чернорука боятся путешествовать по владениям Дымящей Паутины."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_10376 = "Кристальный Клык"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_10376 =
    "Неуловимый паук, редко встречающийся среди населения Нижнего Пика Черной горы. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_10584 = "Урок Роковой Вой"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_10584 =
    "Думвой — истинный лидер огров шпиля. Эта зловещая фигура очаровала своего верного помощника, Верховного Лорда Омокка, коварной магией, позволяющей вместо него контролировать приспешников Рокового Воя. Он приложил все усилия, чтобы продолжить этот фарс, безжалостно убивая всех огров, бросающих вызов правлению верховного лорда."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9736 = "Интендант Зигрис"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9736 =
    "После Первой войны охотник на орков Зигрис прославился тем, что выслеживал беженцев Штормграда и убивал их, как дичь. Он ненавидит клаустрофобные залы Пика Черной горы, но уверен, что придет день, когда он снова будет охотиться на открытом воздухе."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_10220 = "Халикон"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_10220 =
    "Халикон происходит от длинной линии великих воргов, выведенных за их свирепость и преданность. За прошедшие годы мать-берлога произвела на свет поразительное количество диких потомков. Ходят слухи, что она — демоническая собака, подаренная Ренду Чернорукому повелителем преисподней Пылающего Легиона."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_10268 = "Гизрул Работорговец"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_10268 =
    "Очень немногие из Темной Орды видели затворнического и непредсказуемого Гизрула. Зверь выходит из своего темного логова только тогда, когда его партнер, Халикон, зовет его. Эти два чудовищных существа произвели на свет одних из самых крупных и самых свирепых воргов, когда-либо выведенных в истории орков."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9718 = "Гок Башгууд"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9718 =
    "Неуловимый орк, редко встречающийся среди населения Нижнего Пика Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_LBRS_BOSS_NAME_9568 = "Повелитель Вирмталак"
    IJ_DB_DUNGEON_LBRS_BOSS_STORY_9568 =
    "Порождение черного дракона Вирмталак наблюдает за силами нижнего шпиля, готовящимися к нападению на гномов. Он не любит ложную Орду и ее жестоких членов и пожертвует любым количеством приспешников Чернорукого, чтобы защитить своего хозяина Нефариана."

    -- UBRS
    IJ_DB_DUNGEON_UBRS_NAME = "Верхняя часть пика Черной горы"
    IJ_DB_DUNGEON_UBRS_STORY =
    "История этой внушительной крепости долгая и сложная. Верхние пределы Пика Черной горы, высеченные в огненном ядре Черной горы много веков назад кланом Черного Железа и в конечном итоге захваченные черным драконом Нефарианом и его выводком, теперь являются домом для авангарда Железного Марка. Пока продолжается подготовка к использованию Шпиля в качестве плацдарма для полномасштабного вторжения в Азерот, Железная Орда разработала ужасающий план действий на случай непредвиденных обстоятельств: оружие судного дня в самом сердце Черной горы."

    -- UBRS Bosses
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_9816 = "Пирогвардеец Эмберсир"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_9816 =
    "Давным-давно Пирогвард Эмберсир, верный приспешник могущественного Рагнароса Повелителя Огня, сжег десятки орков Черной горы во время решающей битвы в Пылающих степях. В конечном итоге Эмберсир был побежден и заключен в тюрьму в Черной горе, где его мощная энергия теперь перекачивается для использования в ускорении инкубации яиц черного дракона Нефариана."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_10264 = "Солакар Огненный Венок"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_10264 =
    "Завоевать благосклонность стаи черных драконов – неоднозначное благословение. Солакару Огненному Венку поручено заботиться о драконьем порождении Нефариана, но его предупредили, что он заплатит ужасную цену за любого щенка, который умрет под его присмотром или просто не оправдает ожиданий."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_10509 = "Джед Рунвотчер"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_10509 =
    "Неуловимый орк, редко встречающийся среди населения Верхней части Пика Черной горы. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_10899 = "Горалук Трещина Наковальни"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_10899 =
    "Горалук Наковальня — известный кузнец. К сожалению, он продал свою душу сатиру Лораксу, но нарушил сделку и сбежал в Верхнюю часть Пика Черной горы с покрытым рунами нагрудником."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_10429 = "Вождь Ренд Чернорукий"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_10429 =
    "После того, как Орда потерпела поражение во Второй войне, Ренд Чернорук, сын первого вождя, привел остатки своего клана в Пик Черной горы и сразился с дворфами Черного Железа за обладание крепостью. Ренд объединил своих орков с Нефарианом и родом черных драконов, которые разгромили гномов и изгнали их из верховьев Черной горы."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_10430 = "Зверь"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_10430 =
    "Драконий Нефариан испытывает непристойное удовольствие от варварских пыток захваченных приспешников Рагнароса. Несмотря на невообразимую агонию, один из гончих остался в достаточно здравом уме, чтобы его можно было переобучить, а его свирепость делает его идеальным охранником на верхних уровнях Пика Черной горы."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_16042 = "Лорд Валталак"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_16042 =
    "Дворянин-драконид и колдун огромной силы, Валталак был бывшим генералом Пика Черной горы до того, как Драккисат пришел к власти. Он был убит компанией наемников Скрытого Клинка за свою книгу заклинаний, но в конечном итоге даже после своей смерти отомстил за себя, используя свои некромантские силы."
    IJ_DB_DUNGEON_UBRS_BOSS_NAME_10363 = "Генерал Драккисат"
    IJ_DB_DUNGEON_UBRS_BOSS_STORY_10363 =
    "Хитрый и безжалостный стратег, Драккисат командует армиями Нефариана в войне с Рагнаросом. Одержав победу над Темным Железом, силы генерала Драккисата готовы раз и навсегда изгнать гномов из Черной горы."

    -- WC
    IJ_DB_DUNGEON_WC_NAME = "Пещеры плача"
    IJ_DB_DUNGEON_WC_STORY =
    "Много лет назад знаменитый друид Наралекс и его последователи спустились в темные Пещеры Стенаний, названные в честь скорбного крика, который можно услышать, когда пар вырывается из трещин системы пещер. Наралекс планировал использовать подземные источники, чтобы вернуть пышность засушливым Степям. Но войдя в Изумрудный Сон, он увидел, как его видение возрождения превратилось в кошмар наяву, который с тех пор преследует пещеры."

    -- WC Bosses
    IJ_DB_DUNGEON_WC_BOSS_NAME_3653 = "Крэш"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3653 =
    "Древний обитатель Пещер Стенаний, эта гигантская черепаха бродит по подземным пещерам, ее устойчивый разум не подвержен влиянию безжалостных кошмаров Наралекса. Не обманывайтесь его счастливым характером; Креш помешал многим искателям приключений, которые жаждали украсть его массивный панцирь."
    IJ_DB_DUNGEON_WC_BOSS_NAME_3669 = "Лорд Кобран"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3669 =
    "Умение Джарлакслы использовать формы животных принесло ему известность среди друидов Круга Кенария. Однако порча Пещер Стенаний исказила его уникальные способности. Теперь Джарлаксла усовершенствовал смертоносную змеиную форму, переименовав себя в Кобрана, чтобы отразить свою вновь обретенную порочную силу."
    IJ_DB_DUNGEON_WC_BOSS_NAME_5912 = "Отклонившийся сказочный дракон"
    IJ_DB_DUNGEON_WC_BOSS_STORY_5912 =
    "Неуловимый сказочный дракон, редко встречающийся среди обитателей Пещер Стенаний. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_WC_BOSS_NAME_61968 = "Зандара Ветрокрылое Копыто"
    IJ_DB_DUNGEON_WC_BOSS_STORY_61968 =
    "Столь же скользкий, как и сами тени, кентавр Колкар пробрался в скрытую ветвь Извилистой пропасти через узкую из трещин. Возглавляет это вторжение ревностная Зандара Ветрокрылое Копыто, которая смело заявила, что Пещеры Стенаний является ее правом по рождению. Ее присутствие — прямое оскорбление Матери-Земли, не приносящее ничего, кроме разрушения, месту, уже страдающему под тяжестью несбывшейся мечты Наралекса."
    IJ_DB_DUNGEON_WC_BOSS_NAME_3670 = "Лорд Пифас"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3670 =
    "Друг детства Наралекса, воин Арын, быстро изучил друидизм. Несмотря на свою подготовку, послушник был беззащитен перед порчей, лишавшей его рассудка. Арын взял себе имя Пифас, объединив свое впечатляющее мастерство в ближнем бою со своим друидским арсеналом для победы над злоумышленниками."
    IJ_DB_DUNGEON_WC_BOSS_NAME_3674 = "скум"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3674 =
    "Скум впервые отправился в Пещеры Стенаний, чтобы избавиться от враждебной среды Степей. Как и многие другие обитатели пещер, он быстро поддался коррупции. Его вены теперь пульсируют темной энергией, которая превратила его в могучего и безжалостного зверя, которому нет искупления."
    IJ_DB_DUNGEON_WC_BOSS_NAME_61965 = "Вангрос"
    IJ_DB_DUNGEON_WC_BOSS_STORY_61965 =
    "Попытка Наралекса восстановить Степи непреднамеренно породила кошмар наяву, нанеся непоправимый ущерб балансу Калимдора. Вангрос является свидетельством непостоянства этих непроизвольных сил; проявление буйных, буйных зарослей, которые начали двигаться сами по себе внутри каменного лабиринта. Это существо излучает испорченную друидскую магию, служащую опасной мерой против любого, кто пытается пройти по проклятому лабиринту и освободить Мечтателя от его вечного сна."
    IJ_DB_DUNGEON_WC_BOSS_NAME_3673 = "Лорд Серпентис"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3673 =
    "Лидер Друидов Клыка когда-то был лучшим учеником Наралекса. Его трагическое падение произошло из-за его желания стать шан'до, или заслуженным учителем, таким как Наралекс. Когда безумие укоренилось, Серпентис собрал на свою сторону своих собратьев и сформировал Друидов Клыка."
    IJ_DB_DUNGEON_WC_BOSS_NAME_5775 = "Вердан Вечноживущий"
    IJ_DB_DUNGEON_WC_BOSS_STORY_5775 =
    "До прибытия Наралекса в Пещеры Стенаний об этом существе было мало что известно. Считавшийся первоначальным хранителем пещер, Вердан Вечноживущий не смог избежать порчи, постигшей его дом. Вердан объединился с безумными друидами и поддерживает бдительность против тех, кто вторгается в его владения."
    IJ_DB_DUNGEON_WC_BOSS_NAME_3671 = "Леди Анакондра"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3671 =
    "Скарлетлиф была первой, кто вызвался добровольно участвовать в самопровозглашенной миссии Наралекса в Степи. После того, как кошмар ее хозяина разрушил ее разум, юная послушница отбросила свое имя, представляя теперь зловещее рептильное будущее Азерота."
    IJ_DB_DUNGEON_WC_BOSS_NAME_3654 = "Мутанус Пожиратель"
    IJ_DB_DUNGEON_WC_BOSS_STORY_3654 =
    "Из самых темных уголков извращенного разума Наралекса порча, преследующая Изумрудный Сон, проявилась в форме злейших врагов друидов: мурлоков. Аберрация, известная как Мутанус, пришла в бодрствующий мир, чтобы поглотить любого, кто попытается освободить Наралекса из лап Кошмара."

    -- MARA
    IJ_DB_DUNGEON_MARA_NAME = "Мародон"
    IJ_DB_DUNGEON_MARA_STORY =
    "Согласно легенде, Заэтар, сын Кенария, и принцесса элементалей земли Терадрас породили варварскую расу кентавров. Вскоре после создания кентавра безжалостные существа убили их отца. Говорят, что убитая горем Терадрас заперла дух своего возлюбленного в Мародоне, развращая регион. Теперь злобные призраки кентавров и извращенные приспешники-элементали бродят по каждому уголку обширных пещер."

    -- MARA Bosses
    IJ_DB_DUNGEON_MARA_BOSS_NAME_13282 = "Ноксион"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_13282 =
    "Ноксион — живое воплощение коррупции. Терадрас приказала своему союзнику лорду Злоязычку создать этого гнилого элементаля, чтобы он стал могущественным слугой и верным домашним животным, чтобы облегчить одиночество принцессы. Ноксион распространяет свою токсичную сущность в области Мародона, которые еще не засохли под пагубным влиянием Терадраса."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_12258 = "Бритва"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_12258 =
    "Razorlash был создан, чтобы сопровождать Ноксиона через Мародон. Со временем это новое творение стало одним из самых любимых слуг принцессы. Razorlash постоянно бродит по пещерам рядом с Ноксионом, используя колючие усики, чтобы уничтожить любую незапятнанную растительную жизнь, которую он может найти."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_12237 = "Мешлок Жнец"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_12237 =
    "Неуловимый болотный зверь, редко встречающийся среди жителей Мародона. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_12236 = "Лорд Злоязык"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_12236 =
    "Лорд сатиров Злоязык отправился в глубины Мародона, узнав о его порче. Поначалу Терадрас опасался коварного демона, но Зловещий Язык доказал свою ценность, создав для принцессы множество жалких миньонов, таких как Ноксион и Бритва."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_12225 = "Селебрас Проклятый"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_12225 =
    "Узнав о трагической судьбе своего дяди, благородный Келебрас поклялся освободить дух Зейтара. Однако хранитель рощи не был готов к ужасам, ожидавшим его в темных коридорах Мародона. Темные энергии, пропитавшие местность, быстро одолели Келебраса, наполнив его сердце неконтролируемой яростью."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_13601 = "Тинкерер Гизлок"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_13601 =
    "Тинкерер Гизлок и пятеро других охотников за драгоценными камнями пробрались в Мародон, чтобы добыть там очень ценные кристаллы. Их план провалился, когда сатиры перебили всех в отряде, кроме Гизлока. Гоблин, запертый в пещерах и доведенный до грани безумия, считает себя новым правителем подземного региона."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_12203 = "оползень"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_12203 =
    "В течение многих лет древний горный гигант, известный как Оползень, выращивал блестящие хрустальные сады в Мародоне, но Терадрас очаровал чудовище, когда поселился там. Этот некогда стоический гигант теперь живет только для того, чтобы служить своему новому тираническому хозяину."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_13596 = "Гнилохват"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_13596 =
    "Ходят слухи, что Гнилохват обитал в подземных водах Мародона на протяжении тысячелетий. Знаменитый охотник-гном Хемет Эрнестуэй однажды заявил, что зверя невозможно найти, и несколько следопытов-любителей приняли вызов разыскать легендарное существо. Никто из них так и не вернулся."
    IJ_DB_DUNGEON_MARA_BOSS_NAME_12201 = "Принцесса Терадрас"
    IJ_DB_DUNGEON_MARA_BOSS_STORY_12201 =
    "Элементаль земли Терадрас, единственная дочь Теразан Матери Камня, обитает во внутреннем святилище Мародона. Под влиянием Древних Богов принцесса превратила свой дом в логово разложения и страданий. Некоторые полагают, что ее нечистая сила связана с духом ее мертвого возлюбленного Зейтара. Если так, то освобождение павшего хранителя рощи может быть единственной надеждой на очищение Мародона."

    -- RFD
    IJ_DB_DUNGEON_RFD_NAME = "Разорфен Даунс"
    IJ_DB_DUNGEON_RFD_STORY =
    "Легенды гласят, что там, где пал полубог Агамагган, его кровь дала начало огромным массам колючих лоз. Многие свинобразы поселились в самом большом скоплении гигантских шипов, Разорфене, который они почитают как место упокоения Агамаггана. Недавно разведчики сообщили, что видели, как в этом регионе бродит нежить, что порождает опасения, что ужасная Плеть может двинуться на завоевание Калимдора."

    -- RFD Bosses
    IJ_DB_DUNGEON_RFD_BOSS_NAME_7356 = "Чумная Пасть Гниющая"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_7356 =
    "Гниющая мерзость, посланная убить любого искателя приключений, осмелившегося войти в Холмы Бритьего Фена."
    IJ_DB_DUNGEON_RFD_BOSS_NAME_7355 = "Тутенькаш"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_7355 =
    "Хотя Тутен'каш был ослеплен во время Войны Паука до своего обращения в нежить, он по-прежнему служит Плети как один из самых смертоносных командиров склепов. Тутаен'каш компенсирует свою слепоту, украшая свое логово тонкой, почти невидимой паутиной, которая позволяет ему чувствовать каждый шаг и малейшее прикосновение, предупреждая его о необходимости послать миньонов, чтобы устроить засаду на его несчастную добычу. Сильные вибрации могут привести его в дезориентированную ярость, вытащив его из укрытия глубоко в укромных уголках Бритвенных холмов."
    IJ_DB_DUNGEON_RFD_BOSS_NAME_7357 = "Мордреш Огненный Глаз"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_7357 =
    "С помощью некромантической магии Вестник Смерти Блэкторн смог разжечь пламя души Мордреша Огненного Глаза, вернув его к нежити. Будучи бывшим шаманом, Мордреш использовал свой извращенный контроль над стихиями. Он сжигает и опаляет всех, кто угрожает работе Вестника Смерти."
    IJ_DB_DUNGEON_RFD_BOSS_NAME_8567 = "Обжора"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_8567 =
    "Оправдывая свое имя, это массивное чудовище провело большую часть своего времени в Колючих Холмах, объедаясь испорченными трупами кабанов и их хозяев-свинобразов. Масса прогорклого мяса в его кишечнике источает облако ядовитых паров и парализующих болезней, душащих неудачливых искателей приключений, подошедших слишком близко."
    IJ_DB_DUNGEON_RFD_BOSS_NAME_62679 = "Пророк Смерти Ракамег"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_62679 =
    "По мере того как влияние Амненнара Холодоносного расширяется, он назначил Пророка Смерти Ракамега надзирать за сбором темного обсидиана, необходимого для самых гнусных колдовств Лича. Ракамег действует как проводник злобной сущности, распространяющейся через Даунс, проповедуя евангелие нежити перемещенным свинобразам. Он яростно защищает обсидиановые артефакты в бастионе тьмы, рассматривая их как ключ к тому, чтобы бессмертная сущность его хозяина оставалась неуязвимой для тех, кто стремится исправить разломы мира."
    IJ_DB_DUNGEON_RFD_BOSS_NAME_7354 = "Рэгглснут"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_7354 =
    "Неуловимый игообразный кабан, которого редко можно встретить среди жителей Колючего Холма. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_RFD_BOSS_NAME_7358 = "Амненнар Холодоносный"
    IJ_DB_DUNGEON_RFD_BOSS_STORY_7358 =
    "Лич Амненнар начал планировать создание базы для нанесения удара по Оргриммару и Терамору. С этой целью Амненнар нацелился на вербовку недавно перемещенных и отчаявшихся людей свинобразов, пообещав им власть над смертью, чтобы они могли дать отпор захватчикам на своих землях."

    -- RFK
    IJ_DB_DUNGEON_RFK_NAME = "Разорфен Краул"
    IJ_DB_DUNGEON_RFK_STORY =
    "Легенды гласят, что там, где пал полубог Агамагган, его кровь дала начало огромным массам колючих лоз. Многие свинобразы поселились в самом большом скоплении гигантских шипов, Разорфене, который они почитают как место упокоения Агамаггана."

    -- RFK Bosses
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4428 = "Вестник смерти Джаргба"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4428 =
    "Говорящие о Смерти из племени Мёртвой Головы выполняют две функции: распространяют пропаганду и дисциплинируют тех, кто отказывается подчиняться Чарлге Бритва Фланк и, как следствие, её таинственным новым союзникам. Джаргба сделал себе имя среди Вестников Смерти, доминируя над самими умами диссидентов, заставляя их подчиняться воле своих лидеров."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4424 = "Аггем Шиповник"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4424 =
    "Командующий вооруженными силами Иглофенов, военачальник Рамтуск — массивный стареющий свинобраз, чья толстая шкура покрыта шрамами многих сражений с кентаврами, гарпиями, орками и даже тауренами. В более поздние годы Рамтуск присоединился к компании духовных лидеров Свинобразов; Аггем Шиповидное Проклятие и Вестник Смерти Джаргба направляют его мысли из мира духов."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4420 = "Повелитель Рамтуск"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4420 =
    "Командующий военными силами «Мертвой головы», Оверлорд Рамтуск — массивный стареющий свинобраз, чья толстая шкура покрыта шрамами многих сражений с кентаврами, гарпиями, орками и даже тауренами. Вместо того, чтобы замедляться из-за преклонных лет, Рамтуск управляет своими войсками с быстротой и уверенностью закаленного в боях ветерана. Удар по нему наверняка нанесет сокрушительный удар по Мертвой Голове."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4842 = "Заклинатель земли Хальмгар"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4842 =
    "Неуловимый игообразный кабан, которого редко можно встретить среди обитателей Бритвенного Краула. Говорят, что она обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ней..."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_62503 = "Ротторн"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_62503 =
    "Ротторн — живое воплощение корявой природной магии, которая превратила орден Бритвенных Краулов в беспорядок из ежевики и шипов. Первоначально считавшийся продуктом примитивной магии свинобразов, этот элементаль из Ежевичной шкуры на самом деле был доведен до безумия гораздо более темным и зловещим существом, скрывающимся в логове. Теперь он проявляется в состоянии постоянного гнева, самое его сердце — Порченное Ежевичное Сердце — пульсирует чужеродной энергией, которую даже самые опытные друиды находят непостижимой и глубоко тревожной."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4422 = "Агателос Бешеный"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4422 =
    "Кабаны почитаются в культуре свинобразов, а особенно крупные и живучие кабаны считаются благосклонностью Агамаггана. Будучи уже могущественным существом, Агателос был накормлен гуано летучих мышей Краула, которое вызывает сводящий с ума эффект, что приводит к увеличению выносливости и силы. План «Мертвой головы» — использовать Агателоса как мощное оружие, чтобы сокрушить всех, кто им противостоит."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4425 = "Слепой охотник"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4425 =
    "Неуловимая летучая мышь, редко встречающаяся среди жителей Бритвенного Краула. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_RFK_BOSS_NAME_4421 = "Чарлга Бритва Фланк"
    IJ_DB_DUNGEON_RFK_BOSS_STORY_4421 =
    "Лидером (или «старухой») племен Бритвенных фенов является Чарлга Бритва, свинобраз, чьи экспериментальные и мощные методы геомантии не имеют себе равных. Ее стремительный приход к власти и быстро растущее насилие между соплеменниками-свинобразами могут привести только к одному: войне."

    -- SCHOLO
    IJ_DB_DUNGEON_SCHOLO_NAME = "Некроситет"
    IJ_DB_DUNGEON_SCHOLO_STORY =
    "Люди, стремящиеся овладеть силами нежити, хорошо знают Некроситет, печально известную школу некромантии, расположенную в темных и зловещих склепах под Каэр Дарроу. За последние годы сменилось несколько преподавателей, но учреждение остается под контролем Темного магистра Гандлинга, особенно садистского и коварного практика некромантской магии."

    -- SCHOLO Bosses
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10506 = "Киртонос Вестник"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10506 =
    "Давным-давно он стал хозяином Доктора Некроситета Теолена Крастинова. Ответственный за многие злодеяния во время правления Крастинова Некроситетом, Киртонос питался кровью своих невинных жертв. Чтобы задобрить своего хозяина, доктору Крастинову пришлось снабжать горгулью все большим количеством крови."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10503 = "Джендис Баров"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10503 =
    "Джендис Баров когда-то была архимагом Даларана и могущественным иллюзионистом. При жизни она разработала заклинание, которое «показывало несколько изображений ее тела, почти неотличимых от ее реальной формы. Эти изображения дублировали ее действия в разных местах, делая почти невозможным ее обнаружение врагами. Оно было почти безошибочным». После того, как Дом Баров присягнул на верность Культу Проклятых, Джендис превратилась в призрак-нежить в Некроситете."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_11622 = "Рэттлгор"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_11622 =
    "Рэттлгор сделан из останков побежденных врагов. Он и по сей день охраняет Некроситет от злоумышленников."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_14516 = "Рыцарь смерти Тёмный Похититель"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_14516 =
    "Когда-то знаменитый паладин, человек, который впоследствии стал известен как Темный Похититель, был соблазнен зовом Короля-лича и стал коварным рыцарем смерти. Его порча распространилась на его коня, который превратился в лошадь-нежить. Даркривер был отправлен в Некроситет. В подземелье под Великим Оссуарием он пытался подчинить царство духов своей прихоти, вызывая и развращая духов, чтобы они выполняли его приказы."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10433 = "Мардук Блэкпул"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10433 =
    "Мардук Блэкпул, также известный как Мардук Черный, — печально известный рыцарь смерти Плети. Он является наставником в Некроситете и делится своими темными секретами с учениками некромантии."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10432 = "Вектус"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10432 =
    "Вектус разработал чумных драконов, найденных в Некроситете, которых он получил, заплатив Тинки Паробойлу в Пылающих степях за доставку драконьих яиц из Пика Черной горы."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10508 = "Рас Ледяной Шепот"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10508 =
    "Рас Ледяной Шепот когда-то был человеком-магом из Стромгарда. Он был межевым магом, волшебником-изгоем, который никогда не проходил формального обучения в Даларане. Он был одним из первых, кто присоединился к Культу Проклятых и быстро продвинулся по карьерной лестнице. Теперь он надзиратель Некроситета."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_16118 = "Кормок"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_16118 =
    "Кормок — босс-огр-некромант, обитающий в Некроситете. Одна из его голов всегда была весела, хотя и немного глупа, тогда как другая была хитра, расчетлива и имела почти мертвый взгляд. Хотя изначально он был простым магом и не был таким уж плохим членом Скрытого Клинка, он подвергся воздействию некромантской стороны магии и в конечном итоге получил удовольствие от призыва душ изгнанных мертвецов с Острова Очищения. Покинув свою наемную компанию, он поступил в Некроситет."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10505 = "Инструктор Малиша"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10505 =
    "Бывшая высшая эльфийка Кель'Таласа, Малисия была одной из немногих представителей своего вида, добровольно присоединившихся к Культу Проклятых до падения Луносвета. Теперь неживой наставник темных искусств, она наблюдает за физической и тактической подготовкой прислужников школы. Малисия известна своей жестокостью: она часто использует своих учеников в качестве живых мишеней для своей разрушительной теневой магии, чтобы гарантировать, что только самые безжалостные и стойкие выживут и смогут служить Королю-личу."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_11261 = "Доктор Теолен Крастинов"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_11261 =
    "Известный как «Мясник», Крастинов — слуга Киртоноса Вестника и главный мучитель и поставщик тел и частей тел для некромантских экспериментов Некроситета. Его первые жертвы были набраны из числа жителей Каэр Дарроу. Среди них были слуги семьи Баровых Ева и Люсьен Сархофф. Находясь в ловушках, пытаемых и искалеченных в течение нескольких месяцев, они поклялись отомстить Крастинову даже за могилой."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10901 = "Хранитель мудрости Полкелт"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10901 =
    "Хранитель знаний Полкелт когда-то был хранителем знаний, однако эти знания, к сожалению, были утеряны, поскольку теперь он стал неуклюжим и неразумным монстром."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10507 = "Равенианец"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10507 =
    "Равенианец — это чудовищная мерзость беспрецедентного голода, служащая высшей «дисциплинарной» мерой школы. Сшитый из самых сильных останков, доступных культу, он обитает в нижних ямах академии, где его кормят неудачниками и слабыми. В отличие от более разумных преподавателей, Равенианец — существо с чистым, прожорливым инстинктом, действующее как массивная стена гниющей плоти между злоумышленниками и наиболее охраняемыми секретами школы."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10504 = "Лорд Алексей Баров"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10504 =
    "Лорд Алексей Баров был лордом Каэр Дарроу, Брилла, Мельницы Таррен и Южнобережья. Он был отцом Алекси, Уэлдона и Джендис Баров и мужем леди Иллюсии Баров. Подобно Джендис и Иллюсии, он теперь является агентом Плети, обитающей в Некроситете."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_10502 = "Леди Иллюсия Баров"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_10502 =
    "Будучи женой лорда Алексея Барова, Иллюсия участвовала в темном семейном договоре с Кел'Тузадом, обменивая исконные земли Каэр Дарроу на пустое обещание вечной жизни. Теперь призрачная тень своей прежней благородной личности, она часто посещает учебные залы академии. Иллюсия сохраняет аристократическое высокомерие, которое она имела при жизни, используя свое мастерство контроля над разумом и психическую агонию, чтобы сломить волю тех, кто осмелится вторгнуться в оскверненный дом ее семьи."
    IJ_DB_DUNGEON_SCHOLO_BOSS_NAME_1853 = "Темный магистр Гандлинг"
    IJ_DB_DUNGEON_SCHOLO_BOSS_STORY_1853 =
    "Темный магистр Гандлинг — директор Школы некромантии в Каэр Дарроу, назначенный лично Кел'Тузадом."

    -- SFK
    IJ_DB_DUNGEON_SFK_NAME = "Крепость Темного Клыка"
    IJ_DB_DUNGEON_SFK_STORY =
    "Во время Третьей войны волшебники Кирин-Тора сражались против армий нежити Плети. Когда волшебники Даларана погибнут в бою, они вскоре восстанут, добавив свою прежнюю мощь к растущей Плети. Разочарованный отсутствием прогресса (и вопреки советам своих коллег), Архимаг, Аругал решил вызвать существ из других измерений, чтобы поддержать уменьшающиеся ряды Даларана. Призыв Аругала привел хищных воргенов в мир Азерота. Дикие люди-волки перебили не только Плеть, но и быстро напали на самих волшебников. Воргены осадили крепость благородного барона Сильверлейна. Расположенная над крошечной деревушкой Пайревуд, крепость быстро погрузилась в тень и руины. Обезумевший от чувства вины, Аругал усыновил воргенов своими детьми и отступил в недавно получившую название «Крепость Теневого Клыка». Говорят, он до сих пор живет там, защищенный своим огромным питомцем Фенрусом, и преследуемый мстительным призраком барона Сильверлейна."

    -- SFK Bosses
    IJ_DB_DUNGEON_SFK_BOSS_NAME_3914 = "Ретилгор"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_3914 =
    "Ретилгор — один из самых жестоких воргенов, которому архимаг Аругал поручил охранять пленников, пойманных во время взлома Крепости Темного Клыка. В их число входят Ловчий смерти Адамант, Волшебник Эшкромб и Лэнден Стилвелл."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_3886 = "Бритва Коготь Мясник"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_3886 =
    "Острый Коготь обитает в бывшей кухне Крепости Темного Клыка. Он убил множество невинных людей в Крепости Темного Клыка, когда его привел его хозяин Аругал, отсюда и его прозвище."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_3887 = "Барон Сильверлейн"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_3887 =
    "Сильверлейн был бывшим лордом крепости Темного Клыка, но был убит, когда архимаг Аругал и его воргены захватили крепость ради своих зловещих планов. Теперь он часто посещает столовую вместе с некоторыми из своих слуг."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_61969 = "Прелат Железногривый"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_61969 =
    "Некогда человек несравненной веры, прелат Железногривый был известен своими настолько трогательными проповедями, что они волновали сердца даже самых набожных святых. В то время как его другу, отцу Брайткопфу, удалось вернуть себе свободу воли после того, как влияние Короля-лича ослабло, Железногривому повезло меньше. Поглощенный тьмой Крепости Темного Клыка и магией крови Аругала, он остается верным слугой безумия внутри стен. Он представляет собой трагический памятник падшей благодати, владея Светом, который он когда-то проповедовал, как оружием террора против любого, кто пытается положить конец проклятию Крепости."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_4278 = "Командир Спрингвейл"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_4278 =
    "Верный солдат, призрак командира Спрингвейла преследует зал заседаний, используя нечестивые удары, чтобы отомстить за своего лорда, барона Сильверлейна."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_4279 = "Одо Слепой наблюдатель"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_4279 =
    "Одо живет в полуразрушенном деревянном строении, опасно свисающем со стены крепости, с двумя домашними летучими мышами, Blood Seeker и Vile Bat. Хотя он давно потерял зрение (отсюда и его прозвище), он приспособился использовать другие чувства, как и его домашние животные."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_3872 = "Присягнувший смерти капитан"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_3872 =
    "Неуловимый человеческий призрак, редко встречающийся среди населения Крепости Теневого Клыка. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_4274 = "Фенрус Пожиратель"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_4274 =
    "Фенрус — питомец Аругала, архимага Крепости Теневого Клыка. Фенрус рыщет в главном кабинете покоев Аругала. Он невероятно велик, и вполне возможно, что ворг подвергся темной магии от рук Аругала или воргенов."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_3927 = "Мастер волков Нандос"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_3927 =
    "Он является повелителем меньших воргов, и у него есть собственная стая, которая будет сражаться с героями, прежде чем они вступят в бой с ним. Он последний приспешник Аругала, преграждающий путь."
    IJ_DB_DUNGEON_SFK_BOSS_NAME_4275 = "Верховный маг Аругал"
    IJ_DB_DUNGEON_SFK_BOSS_STORY_4275 =
    "Верховный маг Аругал — бывший маг Даларана, который жил в руинах Крепости Теневого Клыка и позже был воскрешен из мертвых на службе Плети. Он наиболее известен тем, что снова выпустил в мир воргенов, освободив их из Изумрудного сна."

    -- STRAT
    IJ_DB_DUNGEON_STRAT_NAME = "Стратхольм"
    IJ_DB_DUNGEON_STRAT_STORY =
    "Когда-то жемчужина северного Лордерона, город Стратхольм, является местом, где принц Артас восстал против своего наставника Утера Светоносного и убил сотни своих подданных, которые, как считалось, заразились ужасной чумой нежити. Вскоре последовало падение Артаса и его окончательная капитуляция перед Королем-личом. Разрушенный город теперь населен нежитью Плети во главе с могущественным личем Кел'Тузадом. Отряд Алых крестоносцев во главе с Великим крестоносцем Датроханом также удерживает часть разрушенного города. Обе стороны ведут постоянные жестокие бои. Те искатели приключений, которые достаточно смелы (или глупы), чтобы войти в Стратхольм, вскоре будут вынуждены сражаться с обеими фракциями. Говорят, что город охраняют три массивные сторожевые башни, а также могущественные некроманты, банши и поганища. Также поступали сообщения о зловредном Рыцаре Смерти, едущем верхом на нечестивом скакуне и обрушивающем без разбора гнев на всех, кто рискует проникнуть в пределы владений Плети."

    -- STRAT Bosses
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10393 = "Череп"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10393 =
    "Неуловимый скелет-маг, редко встречающийся среди населения Стратхольма. Говорят, что он обладает множеством желанных вещей, которые многие хотели бы заполучить, если бы они вообще могли встретиться с ним..."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10558 = "Певец очага Форрестен"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10558 =
    "Очищение Стратхольма унесло жизни бесчисленного количества людей, единственным преступлением которых было пребывание в обреченном городе. Одной из таких жертв стал странствующий певец и пикколоист по имени Форрестен. Он продолжает скитаться по городу после смерти, не в силах смириться со своей трагической судьбой."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10516 = "Непрощенный"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10516 =
    "Лилия была образцом праведности среди своего народа. После того, как Артас приказал своим войскам очистить город, ее рассудок был подорван, когда она увидела, как от ее руки погибло бесчисленное количество невинных людей. Она упала на свой меч, чтобы спастись от окружающего ее безумия, и теперь она существует как призрачное существо, навсегда лишенное отпущения грехов за свои отвратительные деяния."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10808 = "Тимми Жестокий"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10808 =
    "Тиммисон был печально известен своей жестокостью на поле боя. Некоторые полагают, что его садизм возник из-за постоянных издевательств, которым он подвергался в детстве. Теперь он переродился как чудовище Плети, его разум разрушен, его мучают эти воспоминания, заставляя его отвечать на имя, которое он когда-то ненавидел: Тимми."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_11032 = "Малор Ревностный"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_11032 =
    "Безумный член Алого Ордена, он охраняет свой сейф и никого не подпускает к нему."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_11120 = "Багровый Хаммерсмит"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_11120 =
    "Кузнец из Багрового Легиона. О нем мало что известно, кроме того, что он очень защищает свои кузнечные планы."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10997 = "Мастер-пушки Уилли"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10997 =
    "Главный артиллерист Алого ордена, Уилли будет использовать свои пушки независимо от обстоятельств."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10811 = "Архивариус Галфорд"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10811 = "Архивариус Галфорд охраняет архивы Бастиона Алого ордена в Стратхольме."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10812 = "Великий крестоносец Датрохан"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10812 =
    "Великий крестоносец Алого ордена Сайдан Датрохан отдает приказы из Бастиона Алого ордена в Стратхольме. О нем поползли слухи, ставящие под сомнение его истинные намерения и даже его личность..."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10435 = "Мировой судья Бартилас"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10435 =
    "Бартилас был среди невиновных, очищенных Артасом и его войсками во время Очищения Стратхольма. В конце концов Король-лич поднял бывшего магистрата из могилы и приказал огромной нежити-чудовищу охранять его разрушенный дом."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10809 = "Каменный хребет"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10809 =
    "Неуловимая горгулья, редко встречающаяся среди населения Стратхольма. Говорят, что он обладает множеством желанных предметов, которые многие хотели бы заполучить, если бы они вообще могли с ними столкнуться..."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10437 = "Неруб'енкан"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10437 =
    "Неруб'енкан был грозным воином во время Войны Паука. В конце концов, она скончалась от ран и была воскрешена как нежить как послушный приспешник Плети. Теперь нерубианка охраняет зиккурат в Стратхольме так же яростно, как при жизни защищала свой дом."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10436 = "Баронесса Анастари"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10436 =
    "Пока она была жива, Анастари получала то, что хотела, любой ценой. Смерть мало что сделала, чтобы это изменить. Ее душа была вырвана из тела, Анастари превратилась в банши и отказалась от любви к материальным безделушкам в пользу вещей гораздо более зловещего рода."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10438 = "Малеки Бледный"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10438 =
    "Малеки был одним из первых, кто присоединился к Культу Проклятых, проявив огромные способности в использовании могильного холода. Движимый ненасытной жаждой власти, маг пылко оттачивает свои навыки темной магии, чтобы подготовиться к тому моменту, когда его переделают в лича."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10439 = "Рамштайн Пожиратель"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10439 =
    "Рамштайн — одно из самых позорных чудовищ Плети, ужас, сшитый из многочисленных трупов и усиленный непрекращающимся голодом. Это чудовище совершило неописуемые злодеяния над бесчисленными невинными душами, когда силы Плети захватили Стратхольм."
    IJ_DB_DUNGEON_STRAT_BOSS_NAME_10440 = "Барон Ривендер"
    IJ_DB_DUNGEON_STRAT_BOSS_STORY_10440 =
    "Барон Ривендер — могущественный рыцарь смерти на службе Короля-лича, координирующий усилия Плети в Чумных землях. Правя городом Стратхольм, он в настоящее время сражается с агентами Серебряного Рассвета, посланными в Стратхольм, чтобы убить его."

    -- GC
    IJ_DB_DUNGEON_GC_NAME = "Гилнеас Сити"
    IJ_DB_DUNGEON_GC_STORY =
    "Некогда гордая жемчужина полуострова, город Гилнеас превратился в раздробленное поле гражданской войны, драконьей тени и дикого безумия. Хотя Стена Седогрива пала, город остается неприступной крепостью, удерживаемой силами роялистов и их таинственными благодетелями. Под поверхностью восстания, возглавляемого лордом Дариусом Рэйвенвудом, сохраняется более темная гниль: семья Харлоу, секретные агенты рода Черных Драконов, манипулировала гордостью королевства, чтобы подпитывать годы упадка. Искателям приключений придется перемещаться по залитым кровью улицам в поисках утерянных семейных дел, украденных шедевров и древних рукописей гидромантии, одновременно решая окончательную судьбу самого короля Генна Седогрива."

    -- GC Bosses
    IJ_DB_DUNGEON_GC_BOSS_NAME_61419 = "Маттиас Хольц"
    IJ_DB_DUNGEON_GC_BOSS_NAME_61420 = "Погонщик Ярозуб"
    IJ_DB_DUNGEON_GC_BOSS_NAME_61421 = "Судья Сазерленд"
    IJ_DB_DUNGEON_GC_BOSS_STORY_61421 =
    "Человек огромной жестокости, судья Сазерленд председательствовал на беспочвенных судебных процессах по делу о заговоре, в ходе которых одна за другой была убита известная семья Глеймор. Он продолжает выносить свои жестокие приговоры с каждым взмахом молотка, действуя как холодное напоминание о коррупции, которая превратила правосудие королевства в оружие страха."
    IJ_DB_DUNGEON_GC_BOSS_NAME_61422 = "Дастиван Блэккоул"
    IJ_DB_DUNGEON_GC_BOSS_STORY_61422 =
    "Мошенник и корыстный лакей, Дастиван Черный Кожух служит королю Седогриву, как послушный пес. Недавно его наняли для кражи документов на ферму Эбонмер, и он скрывался глубоко в недрах города, чтобы защитить свои нечестные доходы от тех, кто пытается вернуть себе право первородства в семье."
    IJ_DB_DUNGEON_GC_BOSS_NAME_61423 = "Маршал Магнус Грейстоун"
    IJ_DB_DUNGEON_GC_BOSS_NAME_61605 = "Конюший Леввин"
    IJ_DB_DUNGEON_GC_BOSS_STORY_61605 =
    "Информация о конюшне Леввине в настоящее время ограничена, хотя он признан подтвержденным жителем сильно укрепленного города Гилнеас."
    IJ_DB_DUNGEON_GC_BOSS_NAME_61263 = "Семья Харлоу"
    IJ_DB_DUNGEON_GC_BOSS_STORY_61263 =
    "Леди-регент Селия и лорд-регент Мортимер Харлоу — тайные архитекторы упадка королевства. По правде говоря, это Дракониды из рода Черных Драконов, которые долгое время манипулировали гордостью Гилнеаса, чтобы разжигать гражданскую войну и конфликты. Их злые махинации являются корнем драконьего влияния, которое необходимо устранить, чтобы спасти землю."
    IJ_DB_DUNGEON_GC_BOSS_NAME_61418 = "Генн Седогрив"
    IJ_DB_DUNGEON_GC_BOSS_STORY_61418 =
    "Упрямый и гордый король Гилнеаса когда-то был легендарной силой в Альянсе, но теперь он возглавляет разрушающееся королевство. В Башне Седогрива он охраняет Осколок Полночи — развращающий артефакт, подаренный ему лордом Престором. Хотя его власть над нацией ослабла, его сила и гордость делают его опасной добычей для любого, кто стремится положить конец его правлению."

    -- CG
    IJ_DB_DUNGEON_CG_NAME = "Кресент Гроув"
    IJ_DB_DUNGEON_CG_STORY =
    "Спрятанная над водопадами Мистральского озера, Роща Полумесяца когда-то была тихим убежищем, где друиды и мирные жители, такие как Каланар Яркое Сияние, в гармонии ухаживали за лесом. Однако темная тень упала на рощу, затуманивая разумы всех, кто обитает внутри. Фурболги Foulweald, спасаясь от безумия на севере, не нашли здесь прибежища; вместо этого они были объединены в агрессивное племя Гроввельд, а их шаманы и старейшины еще больше разжигали их дикость. Даже защитники-друиды во главе с Хранителем Ранатосом замолчали или оказались искаженными более глубоким и зловещим источником порчи. Теперь Круг Кенария призывает смелые души погрузиться в глубины каменного лабиринта и искоренить зло, гноящееся в сердце рощи, прежде чем оно распространится по всему Калимдору."

    -- CG Bosses
    IJ_DB_DUNGEON_CG_BOSS_NAME_92107 = "Гроветендер Энгрисс"
    IJ_DB_DUNGEON_CG_BOSS_STORY_92107 =
    "Под влиянием стойких заблуждений старейшин фурболгов Гроветендер Энгрисс отказался от своего первоначального долга по защите святилища. Теперь он набрасывается с иррациональной яростью, действуя как неутомимый щит для духовных лидеров, чьи сводящие с ума шепоты полностью исказили его целеустремленность."
    IJ_DB_DUNGEON_CG_BOSS_NAME_92109 = "Хранитель Ранатос"
    IJ_DB_DUNGEON_CG_BOSS_STORY_92109 =
    "Хранитель Ранатос первоначально находился в роще, чтобы отражать распространяющуюся порчу, но его собственные беспорядочные отчеты в конечном итоге сигнализировали о трагическом провале. Теперь полностью испорченный и искажённый, он воплощает в себе то самое зло, с которым когда-то сражался, служа мрачным предупреждением о тьме, которая воцарилась под водопадами Мистральского озера."
    IJ_DB_DUNGEON_CG_BOSS_NAME_92108 = "Верховная жрица А'латея"
    IJ_DB_DUNGEON_CG_BOSS_STORY_92108 =
    "Информация о Верховной жрице А'латее отсутствует в текущих исследованиях Круга Кенария, поэтому она остается призрачной фигурой, обитающей, как известно, только в более глубоких уголках Рощи Полумесяца."
    IJ_DB_DUNGEON_CG_BOSS_NAME_92111 = "Фенектис Обманщик"
    IJ_DB_DUNGEON_CG_BOSS_STORY_92111 =
    "Помимо своей репутации враждебного и хитрого существа в роще, Фенектис Обманщик остается полной загадкой как для ученых, так и для искателей приключений."
    IJ_DB_DUNGEON_CG_BOSS_NAME_92110 = "Мастер Ракксиет"
    IJ_DB_DUNGEON_CG_BOSS_STORY_92110 =
    "Мастер Ракксиет, которого называют ядром разложения в Роще Полумесяца, является зловещим архитектором падения региона. Он процветает за счет страданий и безумия, которые он посеял как среди фурболгов, так и среди друидов-хранителей, и его устранение - единственная надежда предотвратить распространение порчи до Мулгора."

    -- HQ
    IJ_DB_DUNGEON_HQ_NAME = "Карьер Кузни Ненависти"
    IJ_DB_DUNGEON_HQ_STORY =
    "Карьер Кузни Ненависти, раскопанный глубоко в Пылающих степях, изначально был детищем Орвака Стернрока и создан для расширения влияния Союза горняков Черного Железа. Однако закулисный обман привел к смещению Орвака с поста Верховного мастера, замененного мошенником Баргулом Блэкхаммером. С тех пор карьер превратился в улей незаконной деятельности; ходят слухи о том, что летучий «Отвар Кузни Ненависти» тайно готовится, в то время как кислоторожденные элементали проявляются в мощных стоках. Больше всего беспокоит как короля Магни Бронзоборода, так и Орду, прибытие Сумеречного Молота, который двинулся в глубины, чтобы использовать труд Черного Железа в своих апокалиптических целях."

    -- HQ Bosses
    IJ_DB_DUNGEON_HQ_BOSS_NAME_60735 = "Старший бригадир Баргул Черный Молот"
    IJ_DB_DUNGEON_HQ_BOSS_STORY_60735 =
    "Баргул Блэкхаммер годами использовал насилие и закулисную тактику, чтобы узурпировать должность Верховного мастера. Убедив Сенат поддержать его видение карьера Хейтфордж, он успешно сверг своего предшественника путем мошенничества. Теперь, укрывшись в своем украденном офисе, он строго соблюдает приказы Сената, управляя Союзом горняков железной рукой и следя за тем, чтобы истинная, темная цель карьера оставалась защищенной от тех, кого он предал."
    IJ_DB_DUNGEON_HQ_BOSS_NAME_60736 = "Инженер Фигглс"
    IJ_DB_DUNGEON_HQ_BOSS_STORY_60736 =
    "Инженер Фигглс, обладающий эго, которое может соперничать с мастерами Пика Черной горы, является высокомерным вдохновителем, который настаивает на том, чтобы каждое механическое творение называлось своим именем. Он наблюдает за сложной техникой карьера и таинственными планами, связанными с рождением драконов. Его технический гений может сравниться только с его нарциссизмом, что делает его главной целью клана Черной горы, стремящегося остановить технологическую экспансию Черного Железа."
    IJ_DB_DUNGEON_HQ_BOSS_NAME_60829 = "Коррозия"
    IJ_DB_DUNGEON_HQ_BOSS_STORY_60829 =
    "Кислотные лужи в карьере Кузница Ненависти настолько сильны, что в конечном итоге породили злобную сущность чистого растворения. Корроз, возникший в результате химических выбросов секретного процесса пивоварения Черного Железа, представляет собой существо, состоящее из подвижной едкой жидкости. Саму его суть ищут такие мастера-кузнецы, как Фриг Громогорн, которые верят, что в ядре элементаля содержится ключ к закалке оружия невообразимой силы."
    IJ_DB_DUNGEON_HQ_BOSS_NAME_60734 = "Уничтожитель ненависти"
    IJ_DB_DUNGEON_HQ_BOSS_STORY_60734 =
    "Хотя подтверждено, что он проживает в карьере Кузни Ненависти, мало что известно об Аннигиляторе Похитителей Ненависти или о роли, которую он играет в раскопках."
    IJ_DB_DUNGEON_HQ_BOSS_NAME_60737 = "Хар'геш Призыватель Рока"
    IJ_DB_DUNGEON_HQ_BOSS_STORY_60737 =
    "Хар'геш Призыватель Рока — тень, стоящая за трудами Черного Железа, наблюдающая за действиями Сумеречного Молота из самых глубоких уголков карьера. Его присутствие представляет собой прямую угрозу безопасности королевства, побуждая как Альянс, так и Орду требовать его устранения, чтобы предотвратить дальнейшее распространение влияния культа."

    -- KC
    IJ_DB_DUNGEON_KC_NAME = "Каражанские склепы"
    IJ_DB_DUNGEON_KC_STORY =
    "Под тенью Каражана находится подземный склеп, который Кирин-Тор долгое время хранил запечатанным. Это место, где время застопорилось, и здесь обитает «великое зло», которое теперь стремятся уничтожить и Альянс, и Орда. От недостающих страниц книг рецептов гоблинов до «мерзкой черноты» ее самых глубоких уголков, склепы служат мрачным напоминанием о разлагающем влиянии башни на саму землю, на которой она стоит."

    -- KC Bosses
    IJ_DB_DUNGEON_KC_BOSS_NAME_91920 = "Марроуспайк"
    IJ_DB_DUNGEON_KC_BOSS_STORY_91920 =
    "О Костном Шипе известно немногое, поэтому это существо остается загадкой для тех, кто исследует гробницы Каражана."
    IJ_DB_DUNGEON_KC_BOSS_NAME_91929 = "Хиваксис"
    IJ_DB_DUNGEON_KC_BOSS_STORY_91929 =
    "Помимо своей репутации смертоносного обитателя темного оссуария, Хиваксис остается загадкой в ​​гробницах Каражана."
    IJ_DB_DUNGEON_KC_BOSS_NAME_91917 = "Трупоед"
    IJ_DB_DUNGEON_KC_BOSS_STORY_91917 =
    "Документации о мусорщике, известном как Corpsemuncher, не существует, что указывает на то, что он только подтвержденный житель склепов Каражана."
    IJ_DB_DUNGEON_KC_BOSS_NAME_92935 = "Капитан гвардии Горт"
    IJ_DB_DUNGEON_KC_BOSS_STORY_92935 =
    "Исторические тексты не содержат подробностей о жизни или смерти гвардейского капитана Горта, подтверждают лишь его местонахождение внутри склепов Каражана."
    IJ_DB_DUNGEON_KC_BOSS_NAME_91916 = "Архлич Энхраз"
    IJ_DB_DUNGEON_KC_BOSS_STORY_91916 =
    "Наследие Архлича Энхраза совершенно неизвестно, что делает его просто могущественной силой нежити, оккупирующей гробницы Каражана."
    IJ_DB_DUNGEON_KC_BOSS_NAME_91919 = "Командир Андреон"
    IJ_DB_DUNGEON_KC_BOSS_NAME_91928 = "Аларус"
    IJ_DB_DUNGEON_KC_BOSS_STORY_91928 =
    "Известный как Страж склепов, Аларус — главный страж нечистой магии, гноящейся под башней. Кирин-Тор считает его уничтожение жизненно важным для безопасности Азерота, в то время как Орда стремится уничтожить его как акт славы, зная, что только победив это «великое зло», можно рассеять удушающий туман и безумие глубин."

    -- DMR
    IJ_DB_DUNGEON_DMR_NAME = "Отступление Драконьей Пасти"
    IJ_DB_DUNGEON_DMR_STORY =
    "Приют Драконьей Пасти, спрятанный среди ветхих горнодобывающих предприятий далеко на востоке Болотины, служит последним бастионом для закаленных ветеранов Второй войны. После своего поражения в Грим Батоле эти орки собрались под горой, чтобы восстановить свои силы, похищая граждан из гавани Менетил и проводя отвратительные ритуалы, чтобы укрепить свои ряды. Под фанатичным руководством Зулухеда Разбитого, который вернулся с осколок легендарной Души Демона, клан снова начал жестокое подчинение стаи Красных Драконов. Искателям приключений придется перемещаться по нестабильным шахтам и древним дворфийским залам, чтобы подавить влияние Драконьей Пасти, прежде чем их «Темная Орда» сможет возродиться снова."

    -- DMR Bosses
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62057 = "Gowlfang"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62057 =
    "Gowlfang когда-то был лидером гноллов Мошида, прежде чем он бросил свой народ и перешел на сторону орков Драконьей Пасти. Движимый слюнявой, необузданной яростью, этот «большой предатель» теперь возглавляет отколовшуюся группу Мосшидов на службе зеленокожих воинов. Он охраняет вход в горные пещеры с дикой яростью, стремясь доказать свою ценность хозяевам огнедышащих ящеров."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62066 = "Праматерь Пещерной Паутины"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62066 =
    "Орки Драконьей Пасти использовали свое темное искусство, чтобы поработить и магически усилить паукообразных, живущих в шахтах Грим Батола. Мать-Пещера Паутины — ужасающий результат этих ритуалов, обладающая беспрецедентным ядом, вызывающим мучительную боль. Она и ее усиленный выводок действуют как смертоносный защитный механизм, защищающий более глубокие уголки убежища от любого, кто может помешать операциям клана."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62067 = "Веб-мастер Торкон"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62067 =
    "О веб-мастере Торконе имеется мало информации, хотя его присутствие было отмечено как важный обитатель Обители Драконьей Пасти."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62071 = "Гарлок Хранитель огня"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62071 =
    "Гарлок — могущественный повелитель костров, питающий «Вечное пламя», источник мощной энергии, скрытый примитивным колдовством орков. Он защищает эту древнюю магию с фанатичной преданностью, используя пламя для усиления махинаций Драконьей Пасти. Для тех, кто хочет подорвать клан или забрать реликвию Темной Госпожи, Гарлок стоит стеной испепеляющего жара."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62069 = "Халган Редбранд"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62069 =
    "Призрачное напоминание о дварфийском прошлом шахты, Халган Редбранд часто посещает залы, где когда-то работала его семья. Он охраняет Табличку Красноклеймённых, древний образец гномьей типографии, хранящий шокирующую тайну: родословная семьи Красноклеймённых, которую долгое время считали Бронзобородыми, на самом деле лежит глубоко внутри клана Громового Молота. Призрак Халгана – это все, что осталось от этой забытой главы истории Кхаз Модана."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62068 = "Разрушитель Слагкулака"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62068 =
    "Древний каменный голем, все еще выполняющий протоколы первоначальных гномов-строителей шахты, Разрушитель Слагкулака бродит по нестабильным туннелям убежища. Эта разрушающаяся конструкция, питаемая светящимся рунным камнем, рассматривает как орков-оккупантов, так и вторгшихся авантюристов как угрозу, которую следует уничтожить. Это бессмысленный пережиток промышленности, служащий опасным препятствием в темноте."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62070 = "Повелитель Черносерд"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62070 =
    "Настоящий монстр насквозь, Повелитель Черное Сердце является создателем жестоких рейдовых отрядов, терзающих Болотины. Ответственный за похищение и смерть многих жителей гавани Менетил, он является железным кулаком ветеранов Драконьей Пасти. Его смерть как главного военного лидера отступления имеет важное значение для обеспечения безопасности южных земель."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62038 = "Старейшина Полая Кровь"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62038 =
    "Записи о Старейшине Пустокровном чрезвычайно скудны, если не считать того факта, что он является подтвержденным жителем Убежища Драконьей Пасти."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62072 = "Сиристраз"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62072 =
    "Брат Нидисзанца, Сиристраз — благородный красный дракон, в настоящее время страдающий от «тяжелого положения подчинения». Порабощенный Драконьей Пастью, использующей силу Души Демона, он вынужден следовать их отвратительным приказам в древних шахтах. Его болезненные крики эхом разносятся по пещерам, что является трагическим свидетельством продолжающегося подчинения орками стаи Красных Драконов."
    IJ_DB_DUNGEON_DMR_BOSS_NAME_62037 = "Зулухед Потрясенный"
    IJ_DB_DUNGEON_DMR_BOSS_STORY_62037 =
    "Безумный вождь клана Драконьей Пасти Зулухед вернулся в Азерот с мерцающим оскоком первоначальной Души Демона. В то время как некоторые члены его клана, такие как Корлаг Думсонг, считают его трусом, бросившим их ради собственной славы, Зулухед продолжает строить заговоры в подбрюшье Грим Батола. Он по-прежнему полон решимости объединить вождей под своим знаменем, используя испорченную силу осколка, чтобы снова поработить стайку Королевы Драконов."

    -- SWR
    IJ_DB_DUNGEON_SWR_NAME = "Пораженные бурей руины"
    IJ_DB_DUNGEON_SWR_STORY =
    "Остров Балор когда-то был шумным торговым раем, которым управляла семья Балор как процветающее судоходное государство Штормграда. Эта эра торговли и спокойствия закончилась во время Второй войны, когда орки Штормовых Похитителей и Совет Теней принесли разврат на ее берега. Сегодня некогда великолепный замок лежит в руинах на вершине скалы, преследуемый духами тех, кто был привязан к своему прежнему дому демонической жестокостью. Пока SI:7 и гоблины-мусорщики разбирают завалы в поисках утраченных древностей, Совет Теней проводит мерзкие эксперименты в глубинах, угрожая погрузить остров в вечную тьму."

    -- SWR Bosses
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62548 = "Оронок с разбитым сердцем"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62548 =
    "Как одному из самых способных помощников Гул'дана, Ороноку была доверена подвеска Ут'окка, драгоценный камень огромной силы. В настоящее время он скрывается в глубинах руин, наблюдая за новым восстанием Теневого Совета. Его присутствие является напоминанием о ненависти Старой Орды, и он остается главной целью для тех, кто стремится вернуть Орде силу кулона."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62547 = "Дагар Обжора"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62547 =
    "Дагар — презренное существо, чья история злобы восходит к формированию Теневого Совета. Фанатичный последователь наследия Гул'дана, его ненависть пылает, как лавовые лужи Черной горы. Он выступает в роли жестокого силовика в замке, охраняя занятые залы от любого, кто может помешать работе Совета."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62552 = "Библиотекарь Теодор"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62552 =
    "Семья Балор накопила в своей библиотеке невообразимое количество знаний за десятилетия успешной торговли. Теодор в настоящее время является хранителем этих пыльных фолиантов, в том числе скрытых торговых практик, автором которых является сэр Уолтон Бэлор. Он следит за тем, чтобы секреты балорийской торговли не попали в руки шпионов Штормграда."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62549 = "Герцог Балор IV"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62549 =
    "Потомки семьи Балор правили своим островом с зоркими глазами и милосердными душами, пока замок не был проклят. Хотя кости герцога, возможно, превратились в пепел, его присутствие по-прежнему связано с тронным залом. Он — трагическая фигура павшего торгового наследия, его кольцо с символом и корона служат последним оставшимся физическим доказательством былого суверенитета его семьи."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62551 = "Вождь Штормсонг"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62551 =
    "Вождь Штормсонг — важнейшая фигура в цепочке командования Похитителей Шторма, действующая как «глава гидры» оккупации. Он наблюдает за силами орков в руинах, координируя свои действия с Советом Теней, чтобы гарантировать, что их возрождение останется беспрепятственным. Его ликвидация необходима для того, чтобы ослабить власть орков во дворе замка."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62550 = "Повелитель Смерти Погибель Волн"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62550 =
    "Барбарос, капитан Bilgerats, отправился на проклятый остров Балор в погоне за похищенными тайнами и обещанием зарытых сокровищ. Его жадность стала роковой — попав в засаду орков клана Громоразрушителей, он был брошен в темницы замка Громоразрушенных и убит. Однако смерть не стала концом. Тёмные силы, властвующие в этих залах, завладели его телом и вселили в него душу рыцаря смерти, породив Лорда Смерти Прибоекляя. Капитан, некогда покорявший моря, теперь служит сосудом бессмертной тьмы, навеки заточённый в руинах, которые намеревался разграбить."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62652 = "Поработитель Халтас Шейдекрест"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62652 =
    "Помимо его постоянного присутствия в руинах Замка, вызванного бурями, о прошлом и конкретных мотивах Поработителя Халтаса Шейдекреста известно очень мало."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62664 = "Микеллакос"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62664 =
    "Микеллакос — это огромный живой гриб, возникший из источника заражения глубоко под разрушенным замком. Его ядро ​​излучает темную, извращенную магию, которая привела окружающие грибы в состояние неестественной жизни. Поскольку он является основным возбудителем острова, его необходимо очистить, чтобы остановить распространение некротической ткани."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62661 = "Бузинная Пасть Первородная"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62661 =
    "Первобытный зверь, известный как Бузинная пасть, остается загадкой для ученых, и не существует никаких документов, объясняющих его обитание в Руинах, вызванных бурей."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62665 = "Леди Дразаре"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62665 =
    "Исторические отчеты ничего не говорят о леди Дразаре; она признана исключительно как одно из могущественных существ, обитающих в руинах Балора."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62673 = "Игалфор"
    IJ_DB_DUNGEON_SWR_BOSS_STORY_62673 =
    "Высокопоставленный и могущественный колдун Совета Теней, Игал'фор — ученик безумного Чо'галла. Он владеет сломанным кулоном из кровавого камня, чтобы направлять энергию Бездны и вызывать аберрации из-за пределов Пустоты. Его фанатичная преданность своим повелителям-демонам делает его главным архитектором ужасов, происходящих в настоящее время в замке."
    IJ_DB_DUNGEON_SWR_BOSS_NAME_62670 = "Останки Невинного"

    -- FH
    IJ_DB_DUNGEON_FH_NAME = "Лощина Ледяной Гривы"

