    -- MARA
    IJ_DB_POI_MARA_NAME = "Мародон"
    IJ_DB_DUNGEON_FH_STORY =
    "Расположенная глубоко среди замерзших вершин Дун Морога, Лощина Морозной Гривы была оплотом племени Ледяной Гривы задолго до того, как гномы вырубили в горе свои великие залы. Некогда гордый и экспансивный народ, Морозногривы все дальше и дальше отбрасываются в холод из-за неустанного расширения Стальгорна; их охотничьи угодья захвачены, их святыни осквернены. Остатки племени одичали от ярости, совершая набеги на поселения дварфов со свирепостью, рожденной не дикостью, а отчаянием. Для Морозной Гривы это не война. Это выживание."
    IJ_DB_DUNGEON_WHC_STORY =
    "Этот древний каньон был домом для многих племен тауренов, которые в прошлые годы боролись за господство в его текущих водах и убежище от опасностей Калимдора. Культуры и традиции многих людей жили в каньоне Виндхорн, который можно увидеть от древних убежищ, высеченных в склоне горы, до реликвий, желанных тауренами. Недавно таурены Ветророга были изгнаны и изгнаны Зловещим Тотемом, который завоевал его и объявил его своим."
    IJ_DB_RAID_TH_STORY =
    "Эта загадочная лабиринтная сеть туннелей и пещер под горой Хиджал, древняя, как сам Калимдор, была домом фурболгов задолго до Раскола. Его залы священны среди племен и являются местом поклонения их прародителям, богам-близнецам Урсоку и Урсолу. Однако в настоящее время из гнилых пещер вырываются лишь клубы гнилостных паров, а шепоты о почитании грязного бога эхом разносятся по Крепости Древесной Пасти..."
    IJ_DB_POI_WHC_NAME = "Пещеры Виндхорна"
    IJ_DB_POI_TH_NAME = "Крепость Древесной Пасти"
    IJ_DB_POI_TT_NAME = "Туннели Древесной Пасти"
    IJ_DB_DUNGEON_FH_BOSS_NAME_tansha = "Тан'ша Блестящая"
    IJ_DB_DUNGEON_FH_BOSS_STORY_tansha =
    "Лощина Морозной Гривы хорошо хранит свои секреты, в том числе и Тан'ша Блестящая."
    IJ_DB_DUNGEON_FH_BOSS_NAME_ubukaz = "Боевой мастер Убуказ"
    IJ_DB_DUNGEON_FH_BOSS_STORY_ubukaz =
    "Ни хроники, ни записей, ни отчетов — военачальник Убуказ полностью существует вне досягаемости истории."
    IJ_DB_DUNGEON_FH_BOSS_NAME_kanza = "Кан'за Провидец"
    IJ_DB_DUNGEON_FH_BOSS_STORY_kanza =
    "Те, кто вошел в Лощину Ледяной Гривы и дожил до того, чтобы говорить о Кан'зе Провидце, если они вообще существуют, хранят молчание по этому поводу."
    IJ_DB_DUNGEON_FH_BOSS_NAME_hailar = "Хайлар Холодный"
    IJ_DB_DUNGEON_FH_BOSS_STORY_hailar =
    "Ледяные глубины Лощины Ледяной Гривы унесли множество жизней; Узнал ли кто-нибудь из них когда-либо, кем на самом деле был Хайлар Холодный, остается неизвестным."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_vortalus = "Посол Ворталус"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_vortalus =
    "В каньоне Виндхорн нет записей о посол Ворталусе — только титул и угроза, которую он подразумевает."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_pathun = "Патун Сумеречная Шкура"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_pathun =
    "Что бы ни привело Патуна Сумрака в каньон, об этом не было записано. Что бы ни держало его там, тем более."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_ahgktos = "Агк'тос Чистый"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_ahgktos =
    "Чисто в каком отношении и по чьим меркам – те, кто мог бы ответить, давно ушли из каньона Уиндхорн."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_walgan = "Уолган Призыватель Крови"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_walgan =
    "Имя Уолгана Кровавого Призывателя не прошло ни в одной хронике, не оставило никакого следа — ничего, кроме самого имени."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_narlgom = "Говорящий с костями Нарлгом"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_narlgom =
    "Среди Зловещего Тотема, захватившего каньон Ветророга, числится Говорящий с костями Нарлгом — и это все, что известно."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_stormhoof = "Пророк Штормовое Копыто"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_stormhoof =
    "Пророки говорят о будущем. Если Пророк Штормовое Копытце когда-либо и сделал это, то некому было бы это записать."
    IJ_DB_DUNGEON_WHC_BOSS_NAME_shalk = "Вождь Шалк Черный Ветер"
    IJ_DB_DUNGEON_WHC_BOSS_STORY_shalk =
    "Он победил. Он правит. Помимо этого, в каньоне нет ничего от вождя Шалка Блэквинда."
    IJ_DB_RAID_BWL_BOSS_NAME_ezzel = "Ezzel Darkbrewer"
    IJ_DB_RAID_ONY_BOSS_NAME_axelus = "Командир выводка Акселус"
    IJ_DB_RAID_ONY_BOSS_STORY_axelus =
    "Выводок не рассказывает о своих командирах посторонним, а командир выводка Акселус — меньше всего."
    IJ_DB_DUNGEON_FH_BOSS_tansha_ABILITY_NAME_tansha = "Тан'ша Блестящая"
    IJ_DB_DUNGEON_FH_BOSS_tansha_ABILITY_NAME_tanshaintimidatingshout = "Устрашающий крик"
    IJ_DB_DUNGEON_FH_BOSS_tansha_ABILITY_EFFECT_tanshaintimidatingshout =
    "Тан'ша кричит на ближайших врагов, заставляя их в страхе бежать в течение 8 секунд."
