    IJ_QUEST_NAME_2339 = "Найдите драгоценные камни и источник энергии"
    IJ_QUEST_OBJECTIVE_2339 =
    "Заберите у Ульдамана все три драгоценных камня и источник энергии для ожерелья, а затем принесите их Джаркалу Моссмелду в Каргат. Джаркал считает, что источник энергии можно найти в самой мощной конструкции Ульдамана. ||н||  ||н|| Из журнала, знаете ли...\n* Рубин был спрятан в забаррикадированной зоне Shadowforge. ||н|| * Топаз был спрятан в урне в одной из областей Трогга, рядом с гномами Альянса. ||н|| * Сапфир забрал Гримлок, лидер троггов."
    IJ_QUEST_NAME_2318 = "Перевод журнала"
