    IJ_QUEST_OBJECTIVE_7703 =
    "Найдите Рукавицу мощи Гордока и верните ее капитану Кромкрашу в Забытый Город. ||н||  ||н|| По словам Кромкраша, в «старинной истории» говорится, что Тортелдрин — «жуткий» эльф, называвший себя принцем, — украл его у одного из королей Гордока."
    IJ_NPC_NAME_14325 = "Капитан Кромкраш"
    IJ_QUEST_NAME_5525 = "Бесплатный узел!"
    IJ_QUEST_OBJECTIVE_5525 =
    "Он называется «Ключ от кандалов Гордока» — ну, именно так его продолжают называть эти «весёлые люди». Я думаю, что он может быть у любого из огров, но я не уверен, что он есть у кого-то конкретного. Возможно, у охранников больше шансов получить его...\n ||н|| О чем я говорю - оно у вас уже есть, не так ли?! Это там??!"
    IJ_NPC_NAME_14338 = "Узел Наперсточник"
    IJ_QUEST_NAME_5518 = "Костюм огра Гордока"
    IJ_QUEST_OBJECTIVE_5518 =
