    IJ_NPC_NAME_8879 = "Королевский историк Архесонус"
    IJ_QUEST_NAME_3701 = "Тлеющие руины Тауриссана"
    IJ_QUEST_OBJECTIVE_3701 =
    "Отправляйтесь к руинам Тауриссана в Пылающих степях и найдите информацию из реликвий Тауриссана. Вернитесь к королевскому историку Архесонусу, когда получите информацию."
    IJ_QUEST_NAME_4341 = "Каран Могучий Молот"
    IJ_QUEST_OBJECTIVE_4341 =
    "Отправляйтесь в Глубины Черной горы и найдите Харана Могучего Молота. ||н||  ||н|| Король упомянул, что Харан находится там в плену — возможно, вам стоит поискать тюрьму."
    IJ_QUEST_NAME_4322 = "Побег из тюрьмы!"
    IJ_QUEST_OBJECTIVE_4322 =
    "Помогите маршалу Виндзору вернуть свое снаряжение и освободить его друзей. Если вам это удастся, вернитесь к маршалу Максвеллу."
