    IJ_QUEST_NAME_4282 = "Клочок надежды"
    IJ_QUEST_OBJECTIVE_4282 =
    "Верните утерянную информацию маршала Виндзора. ||н||  ||н|| Marshal Windsor believes that the information is being held by Golem Lord Argelmach and General Angerforge."
    IJ_QUEST_NAME_4242 = "Заброшенная надежда"
