    IJ_QUEST_NAME_4186 = "Настоящие мастера"
    IJ_QUEST_OBJECTIVE_4186 = "Отнесите указ Болвара мировому судье Соломону в Приозерье."
    IJ_QUEST_NAME_4223 = "Настоящие мастера"
    IJ_QUEST_OBJECTIVE_4223 = "Поговорите с маршалом Максвеллом в Пылающих степях."
    IJ_QUEST_NAME_4224 = "Настоящие мастера"
    IJ_QUEST_OBJECTIVE_4224 =
    "Поговорите с Рваным Джоном, чтобы узнать о судьбе маршала Виндзора, и вернитесь к маршалу Максвеллу, когда выполните это задание. ||н||  ||н|| Вы помните, как маршал Максвелл говорил вам искать его в пещере на севере."
    IJ_QUEST_NAME_4241 = "Маршал Виндзор"
    IJ_QUEST_OBJECTIVE_4241 =
    "Отправляйтесь к Черной горе на северо-западе и войдите в Глубины Черной горы. Узнайте, что случилось с маршалом Виндзором. ||н||  ||н|| Вы помните, как Рваный Джон говорил о том, что Виндзора утащили в тюрьму."
    IJ_QUEST_NAME_4286 = "Хорошие вещи"
    IJ_QUEST_OBJECTIVE_4286 =
    "Отправляйтесь в Глубины Черной горы и найдите 20 поясных сумок Черного Железа. Вернитесь к Оралиусу, когда выполните это задание. Вы предполагаете, что дворфы Черного Железа в Глубинах Черной горы носят с собой эти хитроумные «поясные рюкзаки»."
    IJ_NPC_NAME_9177 = "Оралиус"
    IJ_QUEST_NAME_4262 = "Мастер Пайрон"
    IJ_QUEST_OBJECTIVE_4262 =
    "Убейте Повелителя Пайрона и вернитесь к Джалинде Сприг. ||н||  ||н|| Вы помните, как Джалинда говорила о Пайроне, охраняющем карьер. Может, стоит поискать там?"
    IJ_NPC_NAME_9561 = "Джалинда Сприг"
    IJ_QUEST_NAME_4263 = "Огненный!"
    IJ_QUEST_OBJECTIVE_4263 = "Найдите Лорда Огненного в Глубинах Черной горы и уничтожьте его!"
    IJ_QUEST_NAME_4128 = "Рагнар Громовар"
    IJ_QUEST_OBJECTIVE_4128 = "Поговорите с Рагнаром Громоваром."
    IJ_NPC_NAME_9540 = "Энохар Громовар"
    IJ_NPC_NAME_1267 = "Рагнар Громовар"
