    IJ_QUEST_OBJECTIVE_4126 = "Принесите утраченный рецепт Громовара Рагнару Громовару в Каранос."
    IJ_QUEST_NAME_3341 = "Принеси конец"
    IJ_QUEST_OBJECTIVE_3341 = "Эндрю Браунелл хочет, чтобы вы убили Амненнара Холодоносного и вернули его череп."
