    IJ_QUEST_NAME_6522 = "Нечестивый союз"
    IJ_QUEST_OBJECTIVE_6522 = "Отнесите Маленький свиток Вариматрасу в Подгород."
    IJ_QUEST_NAME_6521 = "Нечестивый союз"
