    IJ_QUEST_NAME_9015 = "Вызов"
    IJ_QUEST_OBJECTIVE_9015 =
    "Отправляйтесь к Кольцу Закона в Глубинах Черной горы и поместите в его центр Знамя Провокации, поскольку Высший Судья Мрачный Камень выносит вам приговор. Убейте Тельдрена и его гладиаторов и возвращайтесь к Антиону Хармону в Восточных Чумных землях с первой частью амулета лорда Валталака."
    IJ_NPC_NAME_16032 = "Фалрин Древесник"
    IJ_QUEST_NAME_7848 = "Настройка на Ядро"
    IJ_QUEST_OBJECTIVE_7848 =
    "Отправляйтесь к входному порталу Огненных Недр в Глубинах Черной горы и найдите фрагмент ядра. Вернитесь к Лотосу Разлому в Черную гору, когда найдете фрагмент ядра."
