    IJ_QUEST_NAME_3982 = "Что происходит?"
    IJ_QUEST_OBJECTIVE_3982 = "Защитите Гор'шака."
    IJ_NPC_NAME_9020 = "Командир Гор'шак"
    IJ_QUEST_NAME_4001 = "Что происходит?"
    IJ_QUEST_OBJECTIVE_4001 =
    "Поговорите с Хараном Могучим Молотом и соберите информацию о похищении принцессы Мойры Бронзобородой. Отнесите эту информацию Траллу в Оргриммар. ||н||  ||н|| Вы помните, как Гор'шак упомянул, что Харан содержится в камере неподалеку."
    IJ_QUEST_NAME_4002 = "Восточные королевства"
    IJ_QUEST_OBJECTIVE_4002 = "Speak with Thrall if you are prepared to take on the mission he has planned."
    IJ_QUEST_NAME_4003 = "Королевское спасение"
    IJ_QUEST_OBJECTIVE_4003 =
    "Убейте императора Даграна Тауриссана и освободите принцессу Мойру Бронзобородую от его злых чар."
    IJ_QUEST_NAME_3981 = "Командир Гор'шак"
    IJ_QUEST_OBJECTIVE_3981 =
    "Найдите командира Гор'шака в глубинах Черной горы. ||н||  ||н|| Вы помните, что грубо нарисованное изображение орка включало полосы, нарисованные поверх портрета. Возможно, вам стоит поискать какую-нибудь тюрьму."
    IJ_QUEST_NAME_7201 = "Последний элемент"
    IJ_QUEST_OBJECTIVE_7201 =
    "Отправляйтесь в Глубины Черной горы и добудьте 10 эссенций стихий. Ваше первое желание — обыскать големов и их создателей. Помните, Вивиан Лаграв тоже что-то бормотала об элементалях."
    IJ_QUEST_NAME_3906 = "Дисгармония пламени"
    IJ_QUEST_OBJECTIVE_3906 =
    "Отправляйтесь в карьер на Черной горе и убейте Повелителя Пайрона. Вернитесь в Громовое Сердце, когда выполните это задание."
    IJ_NPC_NAME_9084 = "Громовое Сердце"
    IJ_QUEST_NAME_3907 = "Дисгармония огня"
    IJ_QUEST_OBJECTIVE_3907 =
    "Enter Blackrock Depths and track down Lord Incendius. Slay him and return any source of information you may find to Thunderheart."
    IJ_QUEST_NAME_3442 = "Безупречное пламя"
    IJ_QUEST_OBJECTIVE_3442 =
    "Соберите 4 сердца пламени и 4 сферы масла големов и верните эти предметы Велароку Ветрокрылу."
    IJ_NPC_NAME_8479 = "Веларок Ветроклинок"
    IJ_QUEST_NAME_3443 = "Ковка вала"
    IJ_QUEST_OBJECTIVE_3443 = "Принесите 8 кинжалов с ториевым покрытием Велароку Ветрокрылу."
    IJ_QUEST_NAME_3452 = "Корпус Пламени"
    IJ_QUEST_OBJECTIVE_3452 = "Найдите и верните символ Рагнароса Велароку Ветрокрылу."
    IJ_QUEST_NAME_3453 = "Факел возмездия"
    IJ_QUEST_OBJECTIVE_3453 = "Подождите, пока Веларок Ветроклинок завершит Факел Возмездия."
    IJ_QUEST_NAME_3454 = "Факел возмездия"
    IJ_QUEST_OBJECTIVE_3454 = "Возьмите Факел Возмездия."
    IJ_NPC_NAME_149047 = "Факел возмездия"
    IJ_QUEST_NAME_3462 = "Сквайр Мэлтрейк"
    IJ_QUEST_OBJECTIVE_3462 =
    "Поговорите со сквайром Малтрейком."
    IJ_NPC_NAME_8509 = "Сквайр Мэлтрейк"
    IJ_QUEST_NAME_3463 = "Подожгите их!"
